// AWS Cloud Practitioner (CLF-C02) - 150 Questions
const CCP_QUESTIONS = [
{id:'ccp1',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is the primary benefit of cloud computing over traditional on-premises infrastructure?',options:['Pay large upfront capital costs for dedicated hardware and data centers','Trade fixed capital expenses for variable operational expenses — pay only for what you use','Get a 100% uptime guarantee for all services','Eliminate all infrastructure costs with free cloud storage'],correct:1,explanation:'Cloud computing lets you pay only for what you use (variable expenses) rather than investing in data centers upfront (fixed expenses). This is a core advantage of cloud adoption.'},
{id:'ccp2',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'Which AWS support plan provides a Technical Account Manager (TAM)?',options:['Developer — email support with 12-hour response time for general guidance','Business — phone/chat support with 1-hour response for production issues','Enterprise On-Ramp — pooled TAM access and 30-minute response for critical issues','Enterprise — dedicated Technical Account Manager providing proactive guidance and advocacy'],correct:3,explanation:'The Enterprise support plan includes a dedicated Technical Account Manager (TAM) who provides proactive guidance and advocacy.'},
{id:'ccp3',exams:['ccp','saa'],domain:'Cloud Concepts',difficulty:'easy',text:'What does the AWS Shared Responsibility Model state about customer responsibility?',options:['AWS manages all aspects of security including customer data and applications','Customers are responsible for security IN the cloud — data, OS, applications, and identity','Customers are responsible for security OF the cloud — physical infrastructure and hypervisor','AWS handles OS patching and security configuration of all customer EC2 instances'],correct:1,explanation:'Customers are responsible for security IN the cloud (data, OS, apps), while AWS handles security OF the cloud (physical infrastructure, hypervisor).'},
{id:'ccp4',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:"Which of the following best describes 'elasticity' in cloud computing?",options:['The ability to seamlessly move workloads between different cloud providers','The ability to automatically scale resources up or down in response to changing demand','The percentage of time stored data remains intact and uncorrupted over a given period','The geographic distribution of data centers across multiple continents'],correct:1,explanation:'Elasticity is the ability to automatically acquire resources as needed and release them when no longer required.'},
{id:'ccp5',exams:['ccp','saa'],domain:'Cloud Concepts',difficulty:'easy',text:'What is an AWS Region?',options:['A single physical data center that hosts AWS compute and storage equipment','A geographic area containing multiple, isolated Availability Zones connected by low-latency links','An edge location used by CloudFront to cache and deliver content closer to users','A logical grouping of AWS accounts within an organization for billing purposes'],correct:1,explanation:'An AWS Region is a physical location containing multiple isolated Availability Zones within a geographic area.'},
{id:'ccp6',exams:['ccp','saa','dva'],domain:'Security & Compliance',difficulty:'easy',text:'Which AWS service provides a managed firewall to protect web applications from common exploits?',options:['AWS Shield — protects against volumetric DDoS attacks at the network layer','AWS WAF — a managed web application firewall filtering exploits like SQL injection and XSS','Amazon GuardDuty — uses ML to detect threats and anomalous behavior in accounts','AWS Firewall Manager — centrally manages firewall rules across accounts and applications'],correct:1,explanation:'AWS WAF (Web Application Firewall) protects web applications from common exploits like SQL injection and XSS.'},
{id:'ccp7',exams:['ccp','saa','dva'],domain:'Security & Compliance',difficulty:'easy',text:'What is AWS IAM used for?',options:['Amazon CloudWatch — collects and monitors operational metrics and application logs','AWS IAM — manages user identities, access permissions, and policies for AWS resources','AWS KMS — creates and manages encryption keys for securing data at rest and in transit','AWS Shield — detects and protects against distributed denial-of-service (DDoS) attacks'],correct:1,explanation:'AWS IAM manages access to AWS services and resources securely through users, groups, roles, and policies.'},
{id:'ccp8',exams:['ccp','saa'],domain:'Security & Compliance',difficulty:'easy',text:'Which AWS service helps detect threats by continuously monitoring your AWS accounts?',options:['Amazon Inspector — scans EC2 and container images for software vulnerabilities automatically','Amazon Macie — uses ML to discover and classify sensitive data stored in S3 buckets','Amazon GuardDuty — continuously monitors accounts and workloads for malicious or unauthorized activity','AWS Config — records and evaluates AWS resource configuration changes for compliance'],correct:2,explanation:'Amazon GuardDuty is a threat detection service that continuously monitors for malicious activity and unauthorized behavior.'},
{id:'ccp9',exams:['ccp','saa','dva'],domain:'Security & Compliance',difficulty:'easy',text:'What is the principle of least privilege?',options:['Grant all users broad permissions to ensure they can complete any task without friction','Grant only the minimum permissions required for a user or service to perform their function','Share a single set of administrator permissions across all users in the same team','Give account administrators unrestricted access to all AWS services and resources'],correct:1,explanation:'Least privilege means giving users, apps, and systems only the permissions they need and nothing more.'},
{id:'ccp10',exams:['ccp','saa'],domain:'Security & Compliance',difficulty:'easy',text:'Which service provides hardware-based key storage for regulatory compliance?',options:['AWS KMS — a managed service for creating and controlling software-based encryption keys','AWS CloudHSM — dedicated hardware security modules (HSMs) for FIPS 140-2 Level 3 key storage','AWS Secrets Manager — stores and rotates database credentials and application secrets','AWS Certificate Manager — provisions and manages SSL/TLS certificates for AWS services'],correct:1,explanation:'AWS CloudHSM provides dedicated hardware security modules (HSMs) for cryptographic key storage meeting strict compliance requirements.'},
{id:'ccp11',exams:['ccp','dva'],domain:'Technology',difficulty:'easy',text:'Which AWS compute service runs code without provisioning or managing servers?',options:['Amazon EC2 — virtual servers requiring OS management, patching, and capacity planning','Amazon ECS — container orchestration requiring you to define clusters and task definitions','AWS Lambda — serverless compute that runs code in response to events without any server management','Amazon Lightsail — simplified virtual servers with bundled compute, storage, and networking'],correct:2,explanation:'AWS Lambda is a serverless compute service that runs code in response to events without provisioning servers.'},
{id:'ccp12',exams:['ccp','saa','dva'],domain:'Technology',difficulty:'easy',text:'What is Amazon S3 primarily used for?',options:['Amazon EC2 — provides resizable virtual compute capacity for running applications','Amazon S3 — object storage for storing and retrieving any amount of data at any time','Amazon RDS — managed relational database for structured data requiring SQL queries','Amazon CloudFront — a CDN that caches and delivers content from global edge locations'],correct:1,explanation:'Amazon S3 is an object storage service offering scalability, durability, and performance for storing any amount of data.'},
{id:'ccp13',exams:['ccp','saa','dva'],domain:'Technology',difficulty:'easy',text:'Which AWS service is a fully managed relational database service?',options:['Amazon DynamoDB — a serverless NoSQL key-value database with millisecond performance','Amazon Redshift — a petabyte-scale data warehouse optimized for analytical (OLAP) workloads','Amazon RDS — a managed relational database supporting MySQL, PostgreSQL, Oracle, and SQL Server','Amazon ElastiCache — an in-memory caching layer for sub-millisecond data access'],correct:2,explanation:'Amazon RDS makes it easy to set up, operate, and scale relational databases including MySQL, PostgreSQL, Oracle, and SQL Server.'},
{id:'ccp14',exams:['ccp','saa'],domain:'Technology',difficulty:'easy',text:'What is Amazon CloudFront?',options:['Amazon Route 53 — a highly available and scalable DNS web service for domain routing','Amazon CloudFront — a content delivery network (CDN) caching content at global edge locations','Amazon VPC — a logically isolated virtual network for launching AWS resources securely','Amazon CloudWatch — a monitoring service for collecting metrics, logs, and operational data'],correct:1,explanation:'Amazon CloudFront is a CDN that securely delivers data, videos, applications, and APIs globally with low latency.'},
{id:'ccp15',exams:['ccp','saa'],domain:'Technology',difficulty:'easy',text:'Which service enables running containerized applications on AWS without managing servers?',options:['Amazon ECS on EC2 — runs containers on EC2 instances you provision and manage yourself','AWS Fargate — serverless compute for containers requiring no server provisioning or management','Amazon EC2 Auto Scaling — automatically adjusts EC2 instance count based on demand','AWS Elastic Beanstalk — a PaaS that deploys and manages web applications with EC2 underneath'],correct:1,explanation:'AWS Fargate is a serverless compute engine for containers, removing the need to provision and manage servers.'},
{id:'ccp16',exams:['ccp','saa'],domain:'Technology',difficulty:'easy',text:'What does Amazon VPC allow you to do?',options:['Amazon CloudWatch — monitors AWS resource metrics and triggers alarms on thresholds','Amazon VPC — lets you provision a logically isolated virtual network with full IP and routing control','Amazon Route 53 — manages DNS records and routes traffic to AWS and external endpoints','Amazon ElastiCache — caches frequently accessed data in memory for sub-millisecond retrieval'],correct:1,explanation:'Amazon VPC lets you provision a logically isolated section of AWS Cloud where you launch resources in a virtual network you define.'},
{id:'ccp17',exams:['ccp','saa','dva'],domain:'Technology',difficulty:'easy',text:'Which AWS service provides a fully managed NoSQL database?',options:['Amazon RDS — managed relational database supporting SQL workloads with ACID transactions','Amazon Aurora — MySQL and PostgreSQL-compatible relational database with 5x performance gains','Amazon DynamoDB — fully managed, serverless NoSQL database with single-digit millisecond latency','Amazon Redshift — columnar data warehouse optimized for complex analytical queries at petabyte scale'],correct:2,explanation:'Amazon DynamoDB is a fully managed, serverless key-value NoSQL database with single-digit millisecond performance.'},
{id:'ccp18',exams:['ccp','dva'],domain:'Technology',difficulty:'easy',text:'What is AWS Elastic Beanstalk?',options:['Amazon ECS — a container orchestration service for running Docker containers on AWS','AWS Elastic Beanstalk — a PaaS that automatically handles deployment, capacity, load balancing, and scaling','AWS Lambda — a serverless compute service that runs code in response to events','Amazon EKS — a managed Kubernetes service for running containerized workloads at scale'],correct:1,explanation:'AWS Elastic Beanstalk automatically handles deployment, capacity provisioning, load balancing, auto-scaling, and health monitoring.'},
{id:'ccp19',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is the AWS Free Tier?',options:['A bundled support plan that covers technical questions at no additional monthly cost','A promotional program granting permanent free access to all AWS services for all customers','A program offering limited free usage of AWS services for new accounts — including Always Free, 12-Month Free, and trials','A training and certification program providing free AWS exam vouchers to new users'],correct:2,explanation:'The AWS Free Tier lets new customers explore AWS services free of charge, including Always Free, 12 Months Free, and short-term trials.'},
{id:'ccp20',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'Which pricing model offers the largest discount for EC2 instances in exchange for a commitment?',options:['On-Demand — pay per hour with no commitment, highest flexibility but no discount','Spot Instances — up to 90% discount on unused EC2 capacity with the risk of interruption','Reserved Instances — up to 72% discount in exchange for a 1 or 3-year usage commitment','Dedicated Hosts — physical servers dedicated to your use, supporting BYOL licensing'],correct:2,explanation:'Reserved Instances offer up to 72% discount over On-Demand pricing in exchange for a 1 or 3-year commitment.'},
{id:'ccp21',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is AWS Cost Explorer used for?',options:['AWS Security Hub — aggregates and prioritizes security findings across your AWS accounts','AWS Cost Explorer — visualizes and analyzes your AWS spending and usage trends over time','AWS IAM — manages user access and permissions; does not provide cost analysis features','AWS Budgets — sets spending thresholds and sends alerts when costs exceed those limits'],correct:1,explanation:'AWS Cost Explorer lets you visualize, understand, and manage your AWS costs and usage with intuitive graphs and filtering.'},
{id:'ccp22',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'Which AWS tool helps estimate costs before deploying resources?',options:['AWS Cost Explorer — analyzes historical spending and forecasts future costs from actual usage data','AWS Budgets — sets spending alerts but does not estimate costs for hypothetical architectures','AWS Pricing Calculator — estimates the cost of a planned AWS architecture before deployment','AWS Trusted Advisor — reviews existing resources for cost optimization opportunities'],correct:2,explanation:'The AWS Pricing Calculator allows you to estimate the cost of AWS services for your use case before deploying anything.'},
{id:'ccp23',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What are Spot Instances?',options:['Reserved Instances — discounted pricing for committing to a specific instance type for 1 or 3 years','Spot Instances — unused EC2 capacity at up to 90% off, available until AWS reclaims capacity with 2-minute notice','Dedicated Instances — EC2 instances running on hardware dedicated to a single customer','On-Demand Instances — standard per-hour pricing with no upfront commitment or interruption risk'],correct:1,explanation:'Spot Instances use spare EC2 capacity at up to 90% off On-Demand prices. AWS can reclaim them with a 2-minute warning.'},
{id:'ccp24',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'Which of the following is an example of horizontal scaling?',options:['Upgrading an EC2 instance from t3.medium to t3.xlarge to increase its compute capacity','Adding more EC2 instances behind a load balancer to distribute increased workload across multiple servers','Increasing the RAM on an existing database server to improve its in-memory processing speed','Upgrading the CPU on an existing server to a faster processor model for better single-thread performance'],correct:1,explanation:'Horizontal scaling (scale out) adds more instances to distribute load. Vertical scaling (scale up) upgrades existing resources.'},
{id:'ccp25',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is AWS Artifact?',options:['AWS CodePipeline — a CI/CD service for automating software build, test, and release pipelines','AWS Artifact — a self-service portal for downloading AWS compliance reports like SOC, ISO, and PCI DSS','Amazon ECR — a managed container registry for storing, scanning, and deploying Docker images','AWS CloudFormation — a service for provisioning AWS infrastructure using JSON or YAML templates'],correct:1,explanation:'AWS Artifact is a self-service portal for on-demand access to AWS compliance reports like SOC, ISO certifications, and PCI.'},
{id:'ccp26',exams:['ccp','saa','dva'],domain:'Technology',difficulty:'easy',text:'Which service automates infrastructure deployment using code?',options:['AWS CodeDeploy — automates application deployments to EC2, Lambda, and on-premises servers','AWS CloudFormation — provisions and manages AWS resources using infrastructure-as-code templates','AWS CodePipeline — orchestrates the build, test, and deploy stages of a CI/CD release pipeline','AWS CodeBuild — a managed build service that compiles source code and runs unit tests'],correct:1,explanation:'AWS CloudFormation lets you model and provision AWS resources by treating infrastructure as code using JSON or YAML templates.'},
{id:'ccp27',exams:['ccp','saa'],domain:'Technology',difficulty:'easy',text:'What is Amazon Route 53?',options:['Amazon EKS — a managed Kubernetes service for deploying and scaling containerized applications','Amazon Route 53 — a scalable, highly available DNS service and domain registration service','AWS Direct Connect — a dedicated private network connection from on-premises to AWS','Amazon ElastiCache — a managed in-memory caching service for Redis and Memcached workloads'],correct:1,explanation:'Amazon Route 53 is a highly available and scalable DNS web service that routes requests to internet applications.'},
{id:'ccp28',exams:['ccp','saa','dva'],domain:'Security & Compliance',difficulty:'easy',text:'Which AWS service monitors and records API calls made on your account?',options:['Amazon CloudWatch — monitors AWS resource performance metrics and triggers operational alarms','AWS CloudTrail — records all API calls made in your AWS account for auditing and compliance','AWS Config — continuously records and evaluates AWS resource configuration changes','Amazon Inspector — automatically assesses EC2 and container workloads for software vulnerabilities'],correct:1,explanation:'AWS CloudTrail records API calls in your AWS account, providing history for security analysis, resource tracking, and compliance auditing.'},
{id:'ccp29',exams:['ccp','dva'],domain:'Technology',difficulty:'easy',text:'What does Amazon SQS provide?',options:['Amazon Kinesis Data Streams — captures and processes real-time streaming data at massive scale','Amazon SQS — a fully managed message queue that decouples distributed application components','Amazon SNS — a pub/sub service for sending notifications to multiple subscribers simultaneously','Amazon Route 53 — a DNS service that routes internet traffic to the correct AWS endpoints'],correct:1,explanation:'Amazon SQS is a fully managed message queuing service for decoupling and scaling microservices and distributed systems.'},
{id:'ccp30',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What are the six pillars of the AWS Well-Architected Framework?',options:['Security, Reliability, Performance, Cost, Sustainability, Simplicity — six balanced design dimensions','Operational Excellence, Security, Reliability, Performance Efficiency, Cost Optimization, Sustainability — the six pillars','Speed, Security, Scalability, Storage, Serverless, Support — six architectural priorities for cloud workloads','Availability, Security, Monitoring, Optimization, Compliance, Cost — six operational best practice areas'],correct:1,explanation:'The six pillars are: Operational Excellence, Security, Reliability, Performance Efficiency, Cost Optimization, and Sustainability.'},
{id:'ccp31',exams:['ccp','saa'],domain:'Technology',difficulty:'easy',text:'Which AWS service provides a managed Kubernetes service?',options:['Amazon ECS — AWS\'s native container orchestration service using its own control plane and task definitions','AWS Fargate — serverless compute for containers; runs ECS or EKS tasks without managing EC2 nodes','Amazon EKS — a fully managed Kubernetes service for deploying, managing, and scaling containerized applications','AWS Batch — dynamically provisions compute to run batch computing jobs; not a container orchestration service'],correct:2,explanation:'Amazon EKS is a fully managed Kubernetes service that makes it easy to deploy, manage, and scale containerized applications.'},
{id:'ccp32',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is Consolidated Billing in AWS Organizations?',options:['Separates billing by department by creating independent invoices for each business unit\'s AWS account','Combines usage and billing across all member accounts, enabling potential volume discounts on shared tiers','Provides a detailed line-item invoice exclusively for EC2 usage with hourly resource-level cost breakdown','Generates a monthly billing summary sent by email to all account owners within an organization'],correct:1,explanation:'Consolidated Billing lets you consolidate payment for multiple AWS accounts and potentially benefit from combined usage pricing.'},
{id:'ccp33',exams:['ccp','saa'],domain:'Security & Compliance',difficulty:'easy',text:'What is Amazon Inspector used for?',options:['Monitoring AWS cost anomalies and notifying the finance team when spending exceeds configured thresholds','Providing automated vulnerability assessment for EC2 instances, Lambda functions, and container images in ECR','Detecting unusual network activity patterns in VPC traffic that may indicate a security threat or intrusion','Managing and automatically renewing SSL/TLS certificates for use with AWS services like CloudFront and ALB'],correct:1,explanation:'Amazon Inspector is an automated vulnerability management service scanning EC2 instances and container images for vulnerabilities.'},
{id:'ccp34',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is the definition of high availability?',options:['A system that guarantees zero downtime and processes every request without any failures or errors','A system designed to minimize downtime through redundancy, fault isolation, and automatic failover mechanisms','A system backed by a contractual SLA guaranteeing 100% uptime with financial credits for any downtime','A system deployed across all AWS regions to eliminate any single geographic point of failure globally'],correct:1,explanation:'High availability means systems designed to operate continuously with minimal downtime through redundancy and automatic failover.'},
{id:'ccp35',exams:['ccp','saa'],domain:'Security & Compliance',difficulty:'easy',text:'Which AWS service helps protect against DDoS attacks automatically at no extra cost?',options:['AWS WAF — filters malicious web requests like SQL injection and XSS at the application layer','AWS Shield Standard — automatic DDoS protection included with all AWS accounts at no additional cost','AWS Firewall Manager — centrally manages WAF, Shield, and VPC security group rules across accounts','Amazon GuardDuty — uses ML to detect account-level threats like credential abuse and unauthorized access'],correct:1,explanation:'AWS Shield Standard is automatically included with all accounts at no extra cost, protecting against common DDoS attacks.'},
{id:'ccp36',exams:['ccp','saa'],domain:'Technology',difficulty:'easy',text:'What is AWS Direct Connect?',options:['AWS Site-to-Site VPN — creates an encrypted tunnel between on-premises and AWS over the public internet','AWS Direct Connect — a dedicated, private network connection from your on-premises facility directly to AWS','Amazon CloudFront — a CDN that caches and delivers content from edge locations for low-latency access','Amazon Route 53 — a DNS service that routes internet traffic to the appropriate AWS endpoints'],correct:1,explanation:'AWS Direct Connect provides a dedicated private connection between your on-premises network and AWS, bypassing the public internet.'},
{id:'ccp37',exams:['ccp','saa'],domain:'Technology',difficulty:'easy',text:'Which S3 storage class is designed for infrequently accessed data requiring rapid retrieval?',options:['S3 Standard — stores frequently accessed data with low latency and high throughput, highest storage cost','S3 Glacier — low-cost archival storage with retrieval times ranging from minutes to hours, not for rapid access','S3 Standard-IA — designed for infrequently accessed data requiring rapid retrieval with a per-GB retrieval fee','S3 One Zone-IA — stores infrequently accessed data in a single AZ; lower cost but no multi-AZ resilience'],correct:2,explanation:'S3 Standard-IA is designed for data accessed less frequently but requiring rapid access. Lower storage cost but with a retrieval fee.'},
{id:'ccp38',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What does AWS Budgets allow you to do?',options:['Automatically reduce costs when actual spending exceeds the configured budget threshold in real time','Set custom cost and usage budgets that trigger email or SNS alerts when spending meets or exceeds thresholds','Automatically pay your AWS bill each month and maintain a record of all invoices and payment history','Forecast future AWS costs based on historical usage trends without allowing budget alerts or notifications'],correct:1,explanation:'AWS Budgets lets you set custom cost and usage budgets and receive alerts via email or SNS when thresholds are breached.'},
{id:'ccp39',exams:['ccp','saa'],domain:'Cloud Concepts',difficulty:'easy',text:'What is an AWS Availability Zone?',options:['A specific geographic location such as a country or continent where AWS operates infrastructure','One or more discrete data centers with redundant power, networking, and connectivity within a region','A CloudFront point of presence used to cache and deliver content closer to end users globally','A logical grouping of AWS services organized by function such as compute, storage, and database services'],correct:1,explanation:'An AZ consists of one or more discrete data centers with redundant power and networking, providing isolation from failures.'},
{id:'ccp40',exams:['ccp','dva'],domain:'Technology',difficulty:'easy',text:'Which service combination enables serverless APIs?',options:['Amazon EC2 — requires provisioning, managing, and scaling virtual machines to handle API traffic','Amazon API Gateway combined with AWS Lambda — fully serverless: API Gateway routes requests, Lambda executes logic','AWS Elastic Beanstalk — a PaaS for web apps; manages EC2 infrastructure but is not fully serverless','Amazon ECS — orchestrates containerized applications but requires managing the underlying compute layer'],correct:1,explanation:'API Gateway handles request routing and management while Lambda executes your code in response to HTTP requests, enabling serverless APIs.'},
{id:'ccp41',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is the purpose of AWS Trusted Advisor?',options:['Providing 24/7 access to a dedicated AWS support engineer for immediate resolution of critical issues','Offering real-time recommendations aligned to AWS best practices across cost, security, fault tolerance, performance, and service limits','Managing IAM user accounts and permissions to ensure the principle of least privilege is enforced','Monitoring AWS CloudTrail logs for unauthorized API activity and flagging security events in real time'],correct:1,explanation:'AWS Trusted Advisor provides recommendations across five categories: cost optimization, performance, security, fault tolerance, and service quotas.'},
{id:'ccp42',exams:['ccp','saa'],domain:'Technology',difficulty:'easy',text:'What is Amazon Redshift?',options:['Amazon SQS — a fully managed message queue for decoupling distributed application components','Amazon Redshift — a fully managed, petabyte-scale data warehouse optimized for analytical (OLAP) workloads','Amazon DynamoDB — a serverless NoSQL key-value database for high-throughput, low-latency transactional workloads','Amazon ElastiCache — an in-memory caching layer using Redis or Memcached for sub-millisecond data access'],correct:1,explanation:'Amazon Redshift is a fully managed, petabyte-scale data warehouse optimized for analytical (OLAP) workloads.'},
{id:'ccp43',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'Which cloud deployment model keeps all infrastructure on-premises?',options:['Public cloud — all compute and storage resources run on shared AWS infrastructure accessible over the internet','Hybrid cloud — connects on-premises infrastructure with public cloud services for integrated workload management','Private cloud — all infrastructure is owned and operated on-premises, giving the organization full physical control','Community cloud — infrastructure is shared among organizations with common regulatory or mission requirements'],correct:2,explanation:'A private cloud keeps all infrastructure on-premises, giving the organization full control without shared public infrastructure.'},
{id:'ccp44',exams:['ccp','saa','dva'],domain:'Technology',difficulty:'easy',text:'What is Amazon ElastiCache used for?',options:['Storing large binary files and objects such as images, videos, and backups with high durability','Providing fully managed in-memory caching using Redis or Memcached for sub-millisecond data access','Orchestrating containerized workloads across a cluster of EC2 instances using task definitions and services','Managing DNS record sets and routing policies for directing internet traffic to AWS endpoints'],correct:1,explanation:'Amazon ElastiCache provides fully managed in-memory caching (Redis and Memcached) to improve application performance.'},
{id:'ccp45',exams:['ccp','saa','dva'],domain:'Security & Compliance',difficulty:'easy',text:'What is AWS Config?',options:['A configuration file management service for storing application settings and environment-specific parameters','Continuously recording AWS resource configuration changes and evaluating them against compliance rules','A tool for generating and attaching IAM policies to AWS users, groups, roles, and services','A cost anomaly detection service that identifies unusual spending patterns using machine learning models'],correct:1,explanation:'AWS Config continuously monitors and records AWS resource configurations, evaluating them against desired configurations for compliance.'},
{id:'ccp46',exams:['ccp','dva'],domain:'Technology',difficulty:'easy',text:'What is Amazon SNS?',options:['Amazon SQS — a managed queue that holds messages until a single consumer polls and processes them','Amazon SNS — a fully managed pub/sub messaging service that delivers messages to multiple subscribers simultaneously','Amazon Kinesis Data Streams — captures and processes real-time high-volume streaming data records','Amazon SES — a cloud email service for sending transactional, marketing, and bulk email messages'],correct:1,explanation:'Amazon SNS is a fully managed pub/sub messaging service that enables decoupling of microservices through topics and push notifications.'},
{id:'ccp47',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is a Savings Plan in AWS?',options:['A tax-advantaged retirement account offered by AWS to employees based on years of service','A flexible pricing model that provides discounts on EC2, Lambda, and Fargate in exchange for a usage commitment','A way to save billing preferences and payment methods for automatic application to future AWS invoices','An automatic discount program that enterprise customers receive based on their contracted spend level'],correct:1,explanation:'AWS Savings Plans offer up to 72% savings on EC2, Lambda, and Fargate usage in exchange for a 1 or 3-year usage commitment.'},
{id:'ccp48',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:"What is the concept of 'fault tolerance'?",options:['The ability to process and recover from faults quickly through automated scripts and health check responses','The ability of a system to continue operating normally even when one or more components fail or become unavailable','The total amount of time a system is expected to function before requiring maintenance or replacement','The geographic redundancy of cloud regions ensuring data is available across multiple continents simultaneously'],correct:1,explanation:'Fault tolerance is the ability of a system to remain operational when components fail, through redundancy and automatic failover.'},
{id:'ccp49',exams:['ccp','saa'],domain:'Technology',difficulty:'easy',text:'Which AWS service provides global edge locations to reduce latency?',options:['AWS Direct Connect — provides a dedicated private connection from on-premises to AWS, bypassing the internet','Amazon CloudFront — a CDN that caches content at edge locations, reducing latency for static and media delivery','Amazon Route 53 — a DNS service with routing policies including latency-based and geolocation routing','AWS Global Accelerator — routes internet traffic over the AWS global network to the optimal application endpoint'],correct:3,explanation:'AWS Global Accelerator uses the AWS global network to route traffic to optimal endpoints, improving availability and performance.'},
{id:'ccp50',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is a hybrid cloud deployment?',options:['Public cloud — all workloads and data reside entirely on shared AWS infrastructure in the public internet','Hybrid cloud — on-premises infrastructure is connected and integrated with cloud services in a unified architecture','Multi-cloud — workloads are distributed across two or more distinct public cloud providers for flexibility','Private cloud — all resources are hosted in an on-premises data center managed as a cloud-like environment'],correct:1,explanation:'A hybrid cloud connects on-premises infrastructure with cloud resources, allowing workloads to run in the most appropriate environment.'},
{id:'ccp51',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'Which service provides a managed Apache Kafka offering on AWS?',options:['Amazon SQS — a managed message queue for decoupling point-to-point application components asynchronously','Amazon SNS — a pub/sub messaging service that fans out messages to multiple subscriber endpoints at once','Amazon MSK — a fully managed Apache Kafka service for ingesting and processing high-throughput streaming data','Amazon Kinesis — a platform for real-time data streaming including Kinesis Data Streams and Firehose'],correct:2,explanation:'Amazon MSK (Managed Streaming for Apache Kafka) is a fully managed service for Apache Kafka to process streaming data.'},
{id:'ccp52',exams:['ccp','saa'],domain:'Technology',difficulty:'easy',text:'What is Amazon Aurora?',options:['Amazon DynamoDB — a serverless NoSQL key-value database designed for single-digit millisecond latency','Amazon Aurora — a MySQL and PostgreSQL-compatible relational database delivering up to 5x the performance of standard MySQL','Amazon Redshift — a columnar data warehouse for analytical queries and business intelligence workloads','Amazon ElastiCache — an in-memory caching service using Redis or Memcached for sub-millisecond data retrieval'],correct:1,explanation:'Amazon Aurora is a MySQL and PostgreSQL-compatible relational database that is up to 5x faster, with automated backups and multi-AZ replication.'},
{id:'ccp53',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is Amazon Macie?',options:['AWS Shield Advanced — protects web applications against large-scale volumetric and sophisticated DDoS attacks','Amazon Macie — a data security service that uses ML to discover, classify, and protect sensitive data in S3','Amazon GuardDuty — a threat detection service that monitors AWS accounts and workloads for malicious behavior','AWS KMS — a managed service for creating and controlling encryption keys for data at rest and in transit'],correct:1,explanation:'Amazon Macie uses machine learning to automatically discover, classify, and protect sensitive data stored in Amazon S3.'},
{id:'ccp54',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What does "pay-as-you-go" pricing mean in AWS?',options:['Committing to a fixed annual payment covering your entire AWS bill regardless of actual consumption','Paying only for the resources you actually use, measured in seconds or hours, with no long-term contracts','Receiving a single fixed monthly bill calculated at the start of each billing cycle based on provisioned resources','Using AWS services for free for six months before any charges begin to appear on your account'],correct:1,explanation:'Pay-as-you-go pricing means you pay only for the compute, storage, and other resources you actually use, with no long-term contracts.'},
{id:'ccp55',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon ECS?',options:['Amazon EKS — a managed Kubernetes service for running containerized workloads using the Kubernetes API','Amazon ECS — a fully managed container orchestration service for running Docker containers on AWS','AWS Lambda — a serverless compute service that runs event-driven code without managing any servers','AWS CodePipeline — a CI/CD service for automating build, test, and deployment workflows for applications'],correct:1,explanation:'Amazon ECS (Elastic Container Service) is a fully managed container orchestration service for Docker containers.'},
{id:'ccp56',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is the purpose of an Internet Gateway in AWS?',options:['To connect two VPCs within the same region using private IP addresses without traffic traversing the internet','To allow communication between resources in a VPC and the public internet in both directions','To route traffic between Availability Zones within a VPC using the AWS internal network backbone','To provide private connectivity from a VPC to AWS services without using internet gateways or NAT'],correct:1,explanation:'An Internet Gateway enables communication between instances in your VPC and the internet.'},
{id:'ccp57',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is AWS Security Hub?',options:['A physical security operations center where AWS staff monitor data center access and environmental controls','A service providing a centralized dashboard for security findings and compliance status across AWS accounts','A VPN gateway management service for establishing encrypted tunnels between on-premises and AWS VPCs','A firewall rule configuration service for centrally managing security groups and NACLs across accounts'],correct:1,explanation:'AWS Security Hub gives a centralized view of security alerts and compliance status across your AWS accounts and services.'},
{id:'ccp58',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is a Reserved Instance?',options:['An EC2 instance with termination protection enabled that remains running until explicitly stopped by an operator','A pricing model offering up to 72% discounts in exchange for a 1 or 3-year commitment to a specific instance configuration','An EC2 instance that AWS reserves exclusively for internal workloads and is unavailable to customers','A physical server purchased outright from AWS and dedicated entirely to a single customer\'s workloads'],correct:1,explanation:'Reserved Instances offer significant discounts (up to 72%) compared to On-Demand in exchange for committing to a specific instance configuration.'},
{id:'ccp59',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is AWS CloudFormation?',options:['A weather-related monitoring service for tracking real-time environmental conditions at AWS data centers','A service that uses JSON or YAML templates to provision and manage AWS infrastructure as code','A Git-based code repository service for version-controlling application source code and infrastructure definitions','A metrics and log collection service for monitoring the health and performance of AWS resources'],correct:1,explanation:'AWS CloudFormation is an IaC (Infrastructure as Code) service that uses templates to provision and manage AWS resources.'},
{id:'ccp60',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What does Auto Scaling do?',options:['Manually resizes an EC2 instance to a larger type when an administrator determines that capacity is needed','Automatically adds or removes EC2 instances based on real-time demand to maintain availability and reduce costs','Migrates entire databases to new AWS regions or account structures automatically without manual intervention','Manages DNS routing policies to distribute traffic across multiple EC2 instances in different regions'],correct:1,explanation:'Auto Scaling automatically adjusts the number of EC2 instances in response to demand, ensuring availability and reducing costs.'},
{id:'ccp61',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is a Security Group in AWS?',options:['A dedicated team of AWS security specialists assigned to monitor and respond to incidents in customer accounts','A virtual firewall applied at the EC2 instance level, controlling inbound and outbound network traffic','A group of IAM users who share the same permission policies applied at the group level for consistency','An encryption key grouping mechanism for organizing and managing cryptographic keys in AWS KMS'],correct:1,explanation:'A Security Group acts as a virtual firewall at the instance level, controlling inbound and outbound traffic for EC2 instances.'},
{id:'ccp62',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon EBS?',options:['Amazon SES — a cloud-based email sending and receiving service for transactional and bulk emails','Amazon EBS — persistent block storage volumes that attach to EC2 instances like a virtual hard drive','An Elastic Load Balancer — distributes incoming traffic across multiple EC2 instances for high availability','Amazon S3 — object storage for storing and retrieving files, backups, and large amounts of unstructured data'],correct:1,explanation:'Amazon EBS (Elastic Block Store) provides persistent block storage volumes that attach to EC2 instances, similar to a hard drive.'},
{id:'ccp63',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is the purpose of AWS CloudWatch?',options:['Hosting and versioning source code repositories with built-in branch management and pull request workflows','Monitoring AWS resources and applications by collecting metrics, logs, and events for operational visibility','Automating software deployment workflows from source code commits to production infrastructure','Managing IAM user identities and controlling access to AWS services through policies and role assignments'],correct:1,explanation:'Amazon CloudWatch monitors AWS resources and applications, collecting metrics, logs, and events to provide operational visibility.'},
{id:'ccp64',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What does "agility" mean in the context of cloud computing?',options:['The speed at which AWS physically delivers new server hardware to a customer\'s on-premises data center','The ability to quickly provision resources in minutes, experiment rapidly, and deploy new applications without delays','The geographic proximity of AWS data centers to end users that reduces round-trip network latency','The freedom to switch your workloads between different cloud providers without incurring migration costs'],correct:1,explanation:'Cloud agility means being able to quickly spin up resources needed for experiments and deploying new applications in minutes.'},
{id:'ccp65',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is Multi-Factor Authentication (MFA) in AWS?',options:['Granting access to multiple AWS accounts simultaneously using a single set of login credentials','Requiring two or more verification factors — something you know and something you have — to authenticate','Maintaining multiple unique passwords across all services to reduce the impact of a single credential being stolen','Assuming multiple IAM roles simultaneously to access different AWS accounts and services concurrently'],correct:1,explanation:'MFA adds an extra layer of security by requiring users to provide two or more verification factors in addition to their password.'},
{id:'ccp66',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Lightsail?',options:['A simplified version of EC2 with reduced compute power, targeting high-performance scientific workloads','An easy-to-use cloud platform providing preconfigured VPS instances for simple websites and small apps at predictable monthly prices','A low-power edge computing service for IoT devices requiring minimal bandwidth and intermittent connectivity','A simplified S3 storage tier designed for hot data that is frequently accessed by multiple applications'],correct:1,explanation:'Amazon Lightsail is designed for simpler use cases like websites and small apps, offering preconfigured VPS with predictable monthly pricing.'},
{id:'ccp67',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is the AWS Cost and Usage Report (CUR)?',options:['A daily email summary providing a high-level overview of your AWS spending for the previous 24 hours','A detailed dataset containing all AWS cost and usage data with resource-level granularity and pricing metadata','A simplified one-page monthly invoice designed for quick review by non-technical finance stakeholders','An automated tool that identifies cost optimization opportunities and applies recommended changes automatically'],correct:1,explanation:'The CUR provides the most detailed data about your AWS costs and usage, including hourly/daily breakdowns with resource-level granularity.'},
{id:'ccp68',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS Step Functions?',options:['A tool for documenting manual business processes with step diagrams, flowcharts, and approval workflows','A serverless workflow orchestration service for coordinating Lambda functions and AWS services into state machines','A test execution framework specifically designed for running integration tests against Lambda functions','A CI/CD orchestration service for automating software build, test, and deployment pipelines end to end'],correct:1,explanation:'AWS Step Functions orchestrates serverless workflows, letting you coordinate Lambda functions and other services into resilient business processes.'},
{id:'ccp69',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is the benefit of using multiple Availability Zones?',options:['Lower network latency between EC2 instances co-located in the same Availability Zone or data center','Increased fault tolerance and high availability by ensuring a failure in one AZ does not affect other AZs','Reduced AWS pricing through volume discounts automatically applied when usage spans multiple AZs','Simplified IAM policy management by using AZ identifiers as resource conditions in access policies'],correct:1,explanation:'Using multiple AZs means a failure in one AZ does not affect your application in other AZs, providing high availability and fault tolerance.'},
{id:'ccp70',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Kinesis Data Streams used for?',options:['Storing and serving large video files for on-demand streaming with CDN integration and adaptive bitrate','Collecting, processing, and storing streaming data records in real time for real-time analytics applications','Queuing messages between application components for asynchronous, decoupled processing at scale','Storing structured relational data with support for ACID transactions and complex SQL query patterns'],correct:1,explanation:'Amazon Kinesis Data Streams captures, processes, and stores data streams in real time, enabling real-time analytics and processing.'},
{id:'ccp71',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is the purpose of AWS KMS?',options:['A managed Kubernetes service that provisions, manages, and scales container clusters on AWS infrastructure','A managed service for creating, controlling, and rotating cryptographic encryption keys used across AWS services','A monitoring service tracking application and infrastructure performance metrics and alerting on thresholds','A VPN key exchange service that establishes encrypted tunnels between on-premises networks and AWS VPCs'],correct:1,explanation:'AWS KMS (Key Management Service) lets you create and control cryptographic keys used to encrypt your data across AWS services.'},
{id:'ccp72',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon EFS?',options:['Amazon EBS — persistent block storage volumes attached to a single EC2 instance like a virtual hard drive','Amazon EFS — a fully managed elastic NFS file system mountable by multiple EC2 instances simultaneously','Amazon SES — a cloud email service for sending transactional, marketing, and bulk email at high volume','Amazon CloudFront — a CDN that caches content at global edge locations to reduce latency for end users'],correct:1,explanation:'Amazon EFS (Elastic File System) provides scalable, shared NFS file storage that can be mounted by multiple EC2 instances simultaneously.'},
{id:'ccp73',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is AWS Organizations used for?',options:['Managing the organizational chart and reporting hierarchy for employees across business units and teams','Centrally managing multiple AWS accounts, enforcing Service Control Policies, and consolidating billing','Organizing S3 objects into logical folder structures using prefixes for easier navigation and management','Grouping EC2 instances by team or project for simplified tagging, monitoring, and operational management'],correct:1,explanation:'AWS Organizations lets you centrally manage multiple accounts, apply Service Control Policies (SCPs), and consolidate billing across accounts.'},
{id:'ccp74',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is the purpose of an Elastic Load Balancer (ELB)?',options:['Expanding the memory capacity of EC2 instances to allow larger in-memory datasets and faster processing','Distributing incoming application traffic across multiple targets to improve availability and fault tolerance','Dynamically resizing EBS storage volumes to match growth in application data without downtime','Automatically reducing per-request data transfer costs by compressing payloads at the network boundary'],correct:1,explanation:'ELB automatically distributes incoming traffic across multiple targets (EC2, containers, IPs) improving availability and fault tolerance.'},
{id:'ccp75',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What does "global infrastructure" mean in AWS?',options:['AWS employs staff in every country and territory to provide local support and account management services','AWS operates Regions and Availability Zones worldwide, enabling customers to deploy close to their users globally','AWS provides automatic content translation services enabling applications to serve users in their native language','AWS shares infrastructure and data across all countries to ensure compliance with global trade agreements'],correct:1,explanation:"AWS's global infrastructure spans Regions and AZs worldwide, allowing customers to serve end users with low latency wherever they are."},
{id:'ccp76',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is a Network Access Control List (NACL)?',options:['A firewall rule specifying which individual IP addresses are permitted to connect to an EC2 instance via SSH','An optional stateless firewall at the subnet level controlling inbound and outbound traffic with numbered rules','An access list for approved network administrators who can modify VPC configurations and routing tables','An approved list of AWS services that an account is permitted to use based on organizational security policies'],correct:1,explanation:'NACLs act as a stateless firewall at the subnet level, controlling inbound and outbound traffic with numbered rules.'},
{id:'ccp77',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS Glue?',options:['A utility for physically attaching and mounting EBS volumes to running EC2 instances in a VPC','A fully managed serverless ETL service for discovering, transforming, and integrating data for analytics','A service for merging multiple AWS accounts into a single consolidated billing and governance structure','A compilation service that transforms infrastructure code templates into deployable CloudFormation stacks'],correct:1,explanation:'AWS Glue is a serverless data integration service that makes it easier to discover, prepare, move, and integrate data for analytics.'},
{id:'ccp78',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Athena?',options:['A centralized monitoring dashboard for visualizing operational metrics and configuring alarms in real time','An interactive query service for analyzing data directly in S3 using standard SQL with no servers to manage','A real-time streaming data processing platform for ingesting and analyzing millions of events per second','A machine learning training and deployment service for building custom predictive models at scale'],correct:1,explanation:'Amazon Athena lets you run SQL queries directly against data stored in Amazon S3 with no infrastructure to manage, paying per query.'},
{id:'ccp79',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'Which AWS service provides recommendations to reduce costs based on actual usage?',options:['AWS Pricing Calculator — estimates the cost of a planned architecture before any resources are deployed','AWS Trusted Advisor — analyzes your existing usage and recommends cost savings for idle and underutilized resources','AWS Budgets — sets spending thresholds and sends alerts when actual or forecasted costs exceed limits','AWS Cost Explorer — visualizes historical spending and forecasts future costs based on usage trends'],correct:1,explanation:'AWS Trusted Advisor analyzes your usage and provides recommendations for cost savings, including identifying idle or underutilized resources.'},
{id:'ccp80',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Comprehend?',options:['A learning management platform for developer training, certification preparation, and skills assessment','A natural language processing service that extracts insights, entities, and sentiment from unstructured text','A document archiving and retrieval service for storing and searching large volumes of scanned files','A code comprehension tool that explains and documents complex code using AI-assisted analysis'],correct:1,explanation:'Amazon Comprehend uses machine learning to find insights and relationships in unstructured text without requiring ML expertise.'},
{id:'ccp81',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is AWS Secrets Manager?',options:['A classification system for storing and managing government and military classified information assets','A service for securely storing, rotating, and retrieving secrets like database credentials and API keys','A physical hardware security module for storing cryptographic keys with FIPS 140-2 Level 3 compliance','A password vault built into AWS IAM for enforcing password complexity policies and rotation schedules'],correct:1,explanation:'AWS Secrets Manager helps protect access to applications by securely storing, managing, and rotating secrets like database credentials and API keys.'},
{id:'ccp82',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon SageMaker?',options:['A project management and team collaboration tool for planning sprints and tracking engineering work','A fully managed platform for building, training, and deploying machine learning models at scale','A container cluster management service that handles scheduling, networking, and scaling of containerized apps','A live video streaming and on-demand media delivery platform with built-in encoding and DRM support'],correct:1,explanation:'Amazon SageMaker provides every developer and data scientist with the ability to build, train, and deploy ML models quickly.'},
{id:'ccp83',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is cloud bursting?',options:['A scenario where a cloud application exceeds its performance limits and crashes under sudden heavy load','A deployment strategy where applications run in private infrastructure but overflow into public cloud during demand spikes','A security event where an application exceeds its AWS account service quotas and triggers throttling','A data replication failure that occurs when cross-region replication lags behind the primary data source'],correct:1,explanation:'Cloud bursting lets applications run in a private cloud but automatically expand into public cloud resources when demand exceeds private capacity.'},
{id:'ccp84',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What does Amazon Rekognition do?',options:['A version control and code hosting service for managing application source code and collaborative workflows','A computer vision service that analyzes images and videos for objects, faces, text, and activities using deep learning','An operational monitoring service that tracks EC2 instance performance metrics and generates dashboards','A DNS routing service that recognizes and directs requests to the nearest or healthiest available endpoint'],correct:1,explanation:'Amazon Rekognition is a computer vision service that adds image and video analysis to your applications using deep learning.'},
{id:'ccp85',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is an AWS account root user?',options:['The first IAM administrative user created by following AWS security best practices during account setup','The identity created at account registration with unrestricted access to all AWS services and account settings','A special read-only role used exclusively by AWS support engineers to access your account for troubleshooting','An account type reserved solely for managing billing and invoicing, separate from operational workload access'],correct:1,explanation:'The root user is created when you first set up an AWS account and has unrestricted access. Best practice is to use IAM users for daily tasks.'},
{id:'ccp86',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Polly?',options:['A managed service for collecting and analyzing survey responses from large distributed user populations','A text-to-speech service that converts written text into natural-sounding speech using deep learning models','A real-time polling service that queries multiple endpoints simultaneously and aggregates their responses','A network infrastructure monitoring tool that detects packet loss and latency across distributed systems'],correct:1,explanation:'Amazon Polly uses advanced deep learning to synthesize natural-sounding human speech from text.'},
{id:'ccp87',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS DataSync?',options:['A schema change management service for synchronizing database versions across development environments','A managed service for accelerating and automating data transfers between on-premises storage and AWS','A real-time event streaming service for ingesting millions of data records per second from distributed sources','A live database migration service that replicates data from one database engine to another with minimal downtime'],correct:1,explanation:'AWS DataSync simplifies, automates, and accelerates the transfer of data between on-premises storage systems and AWS storage services.'},
{id:'ccp88',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is Amazon Cognito?',options:['A cognitive computing platform for building AI-powered enterprise applications using natural language','A service for adding user sign-up, sign-in, social login, and access control to web and mobile applications','A document processing database that uses cognitive indexing to automatically categorize stored records','An AI security service that monitors user behavior patterns to detect unusual or anomalous activity'],correct:1,explanation:'Amazon Cognito lets you add user authentication and authorization to your web and mobile apps quickly and easily.'},
{id:'ccp89',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS IoT Core?',options:['A managed service for running traditional on-premises workloads without changes on cloud infrastructure','A managed cloud platform for securely connecting IoT devices and routing their messages to AWS services','A network speed and quality testing service for diagnosing internet connectivity issues from AWS regions','A core networking component that manages routing tables and internet gateways within Amazon VPC'],correct:1,explanation:'AWS IoT Core is a managed service that lets connected devices interact securely with cloud applications and other devices.'},
{id:'ccp90',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is the AWS Marketplace?',options:['A physical retail store operated by AWS for purchasing hardware, developer tools, and AWS merchandise','A digital catalog of thousands of third-party software solutions and data sets that run on AWS','An internal job posting platform where AWS partners can list open positions for certified professionals','A secondary marketplace for customers to sell unused Reserved Instance capacity to other AWS users'],correct:1,explanation:'AWS Marketplace is a digital catalog of third-party software, data, and services that run on AWS, simplifying procurement and deployment.'},
{id:'ccp91',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Translate?',options:['A legal contract management service for generating, reviewing, and storing compliance documentation','A neural machine translation service providing fast, high-quality, and cost-effective language translation','A DNS protocol translation service converting domain names to IP addresses across geographic regions','A code language conversion tool for porting applications between programming languages automatically'],correct:1,explanation:'Amazon Translate is a neural machine translation service that delivers fast, high-quality, and affordable language translation.'},
{id:'ccp92',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is AWS Control Tower?',options:['A physical operations center where AWS staff oversee data center security, cooling, and power management','A governance service that sets up a secure, compliant, multi-account AWS landing zone following best practices','A network traffic management service for controlling data flow between VPCs and on-premises environments','A centralized security monitoring dashboard for aggregating findings from GuardDuty, Inspector, and Macie'],correct:1,explanation:'AWS Control Tower automates the set up of a baseline environment (landing zone) for multi-account governance following AWS best practices.'},
{id:'ccp93',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Forecast?',options:['A weather data aggregation and visualization service for tracking environmental conditions at AWS facilities','A fully managed ML-based service for generating highly accurate time-series forecasts from historical data','A budget planning tool for tracking capital expenditures across multiple teams and business units','A capacity planning dashboard that recommends appropriate EC2 instance types based on forecast usage'],correct:1,explanation:'Amazon Forecast uses machine learning to generate accurate forecasts from time-series data without requiring ML expertise.'},
{id:'ccp94',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is the difference between CapEx and OpEx in cloud computing?',options:['CapEx represents ongoing cloud costs; OpEx represents the upfront purchase of on-premises hardware','CapEx is the large upfront investment in on-premises hardware and facilities; OpEx is the ongoing cloud pay-per-use model','Both terms refer to the same type of spending; the distinction is irrelevant in modern cloud architectures','CapEx is always more expensive than OpEx when comparing cloud versus on-premises infrastructure costs'],correct:1,explanation:'Traditional IT uses CapEx (large upfront investment in hardware). Cloud shifts this to OpEx (ongoing operational expenses), improving cash flow.'},
{id:'ccp95',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS CodePipeline?',options:['A browser-based IDE for writing, reviewing, and merging application code within a collaborative team environment','A fully managed continuous delivery service that automates build, test, and deployment pipelines','A manual code review platform for requesting peer reviews and tracking approval workflows in repositories','A performance load testing service for simulating traffic patterns and identifying application bottlenecks'],correct:1,explanation:'AWS CodePipeline is a fully managed CD service that automates your build, test, and deploy phases each time there is a code change.'},
{id:'ccp96',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is a VPN in AWS context?',options:['A Virtual Private Network creating an encrypted internet-based tunnel between on-premises networks and a VPC','A type of EC2 instance optimized for high memory workloads such as in-memory databases and analytics','A Virtual Private Node in a distributed computing cluster providing isolated processing for sensitive jobs','A billing category in AWS Cost Explorer for organizing network-related charges by connectivity type'],correct:0,explanation:'An AWS VPN creates an encrypted tunnel between your on-premises network (or client) and your Amazon VPC over the public internet.'},
{id:'ccp97',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Lex?',options:['A legal document drafting and review service for generating compliance agreements and contracts','A service for building conversational interfaces using voice and text input powered by the same AI as Alexa','A lexical code analysis tool for identifying syntax errors and style violations in software repositories','A low-latency edge networking service for routing traffic between VPCs and on-premises data centers'],correct:1,explanation:'Amazon Lex is a service for building conversational interfaces using automatic speech recognition and natural language understanding.'},
{id:'ccp98',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is the purpose of AWS Personal Health Dashboard?',options:['A health tracking application that integrates with wearable devices to monitor personal fitness metrics','A personalized dashboard showing alerts and remediation guidance for AWS events affecting your specific resources','A real-time monitoring dashboard for EC2 CPU, memory, and network performance metrics and alarms','A billing health report that analyzes spending patterns and flags anomalous charges on your AWS account'],correct:1,explanation:'AWS Health Dashboard provides personalized alerts and remediation guidance when AWS is experiencing events that may affect your resources.'},
{id:'ccp99',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Textract?',options:['A rich text editor for creating formatted documents with collaborative commenting and version tracking','A service that extracts text, forms, tables, and structured data from scanned documents using ML','A neural machine translation service for converting text between languages with high accuracy','A content moderation service that detects and filters inappropriate images and text in user submissions'],correct:1,explanation:'Amazon Textract uses ML to automatically extract text and data from scanned documents, going beyond simple OCR to identify structure.'},
{id:'ccp100',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is the AWS Snow Family?',options:['A series of seasonal promotional events offering limited-time discounts on AWS services globally','Physical devices for migrating large datasets into and out of AWS when internet transfer is impractical','A family of lightweight EC2 instances optimized for cold storage use cases with minimal compute overhead','A regional program providing specialized AWS services and pricing for customers in Nordic countries'],correct:1,explanation:'The AWS Snow Family (Snowcone, Snowball, Snowmobile) are physical devices used to transfer large amounts of data to AWS when network transfer is too slow or impractical.'},
{id:'ccp101',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is AWS WAF used to protect against?',options:['Physical theft prevention systems for AWS server hardware stored in data centers around the world','A web application firewall that blocks common attacks like SQL injection, XSS, and application-layer DDoS','A service for preventing unauthorized access to AWS accounts using multi-factor authentication policies','A data integrity verification service that detects and corrects silent data corruption in S3 storage'],correct:1,explanation:'AWS WAF protects web applications by filtering malicious web traffic, blocking common attack patterns like SQL injection and XSS.'},
{id:'ccp102',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Connect?',options:['A physical fiber networking service connecting enterprise data centers to AWS regions via dedicated cables','A fully managed cloud contact center enabling omnichannel customer service at lower operational cost','A networking service for establishing private connectivity between multiple VPCs within a single region','An integration hub for connecting AWS partner solutions and external SaaS applications into your workflows'],correct:1,explanation:'Amazon Connect is an easy-to-use omnichannel cloud contact center helping companies provide superior customer service at lower cost.'},
{id:'ccp103',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What does "right-sizing" mean in AWS?',options:['Physically sizing servers to match the specific rack dimensions required for a data center installation','Selecting instance types and sizes that match actual workload needs to avoid waste and reduce compute costs','Configuring S3 bucket storage limits to prevent uncontrolled growth and enforce data retention policies','Standardizing the entire organization on a single EC2 instance family to simplify procurement and support'],correct:1,explanation:'Right-sizing means analyzing and selecting the most cost-effective EC2 instance types/sizes that still meet your performance requirements.'},
{id:'ccp104',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is the AWS Well-Architected Tool?',options:['A physical measurement tool used by AWS engineers to verify server rack dimensions during installation','A service that reviews your workload architecture against the six pillars of the Well-Architected Framework','A code quality analysis tool that scores software against industry standards and best practice guidelines','A project management platform for tracking AWS migration timelines, milestones, and team responsibilities'],correct:1,explanation:'The AWS Well-Architected Tool helps you review your architecture against best practices across the six pillars and provides guidance for improvements.'},
{id:'ccp105',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS Batch?',options:['A batch food preparation and doorstep delivery service operated as an AWS marketplace offering','A fully managed service for running hundreds of thousands of batch computing jobs dynamically on AWS','A command-line tool for uploading large numbers of files to S3 buckets in parallel using multipart upload','A group messaging and notification service for broadcasting updates to multiple team channels simultaneously'],correct:1,explanation:'AWS Batch dynamically provisions compute resources and schedules batch computing jobs based on volume and resource requirements.'},
{id:'ccp106',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is the AWS Acceptable Use Policy?',options:['A document specifying the acceptable ambient temperature and humidity ranges inside AWS data centers','A policy describing prohibited uses of AWS services, including illegal activities and harmful content','A reference guide for writing valid IAM policy JSON syntax with correct action and resource formatting','A usage agreement governing how AWS bills customers for services consumed under a committed spending plan'],correct:1,explanation:'The AWS Acceptable Use Policy (AUP) describes prohibited uses of AWS services, including illegal activity, harmful content, and security violations.'},
{id:'ccp107',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Transcribe?',options:['A managed document digitization service for converting physical paper files into searchable digital archives','An automatic speech recognition service that converts spoken audio into accurate text transcriptions','A utility for duplicating and distributing files between storage systems using high-speed network links','An interactive language learning platform that uses AI to coach pronunciation and grammar in real time'],correct:1,explanation:'Amazon Transcribe uses automatic speech recognition (ASR) to convert speech to text, useful for transcribing customer calls and media content.'},
{id:'ccp108',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is an IAM policy?',options:['A written security standard published by AWS governing the physical protection of all data center facilities','A JSON document defining which AWS actions are allowed or denied on which resources for which principals','A billing agreement for Reserved Instance pricing that specifies the commitment period and payment schedule','A network routing configuration that determines how traffic flows between subnets within an Amazon VPC'],correct:1,explanation:'An IAM policy is a JSON document that defines permissions, specifying which actions are allowed or denied on which AWS resources.'},
{id:'ccp109',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What does AWS X-Ray do?',options:['A non-destructive imaging service for scanning physical AWS server hardware for defects or wear','A distributed tracing service that provides end-to-end visibility into requests flowing through distributed applications','A red team penetration testing service for identifying vulnerabilities in application APIs and databases','An interactive data visualization tool for building custom dashboards from AWS operational metrics'],correct:1,explanation:'AWS X-Ray helps developers analyze and debug distributed applications by providing end-to-end view of requests and identifying performance bottlenecks.'},
{id:'ccp110',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is a Dedicated Host?',options:['A web hosting subscription plan for running dedicated websites with a reserved domain name and IP address','A physical EC2 server dedicated to your use that supports per-socket or per-core BYOL license compliance','An S3 bucket with private access and a dedicated IP address for serving static content without public exposure','A named AWS support engineer assigned exclusively to a customer for handling all technical inquiries'],correct:1,explanation:'A Dedicated Host is a physical server with EC2 instance capacity fully dedicated to your use, useful for regulatory requirements and BYOL licensing.'},
{id:'ccp111',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Timestream?',options:['A video editing service that adds timestamps and chapter markers to recorded content for easy navigation','A fast, scalable, and fully managed time series database purpose-built for IoT and operational applications','A shared team calendar service for scheduling meetings, resource bookings, and milestone tracking','A task scheduling service for running cron-based jobs on a fixed recurring interval without servers'],correct:1,explanation:'Amazon Timestream is a purpose-built time series database that makes it easy and cost-effective to store and analyze trillions of time series data points.'},
{id:'ccp112',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is Amazon Detective?',options:['An interactive mystery game hosted on AWS for team-building events and developer engagement activities','A security service that uses ML to analyze and visualize security data and help investigate potential incidents','A real-time fraud detection service for e-commerce platforms that flags suspicious purchasing behavior','A static code analysis tool that scans source code repositories for known vulnerabilities and exposures'],correct:1,explanation:'Amazon Detective makes it easy to analyze, investigate, and quickly identify the root cause of potential security issues or suspicious activities.'},
{id:'ccp113',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is a Service Level Agreement (SLA) in AWS?',options:['A legally binding contract signed by a named AWS account manager committing to specific service levels','A formal AWS commitment to specific service uptime or performance targets with credits if those targets are missed','A public reference document listing all features, capabilities, and regional availability of each AWS service','A technical support agreement specifying the types of issues covered and required response time commitments'],correct:1,explanation:'An SLA is a formal commitment by AWS about service availability. If the SLA is not met, customers may receive service credits.'},
{id:'ccp114',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS AppSync?',options:['A mobile app synchronization service that backs up device data to AWS storage for cross-device access','A fully managed GraphQL service for building flexible APIs that securely connect apps to multiple data sources','A deployment pipeline synchronization tool that coordinates parallel build and release stages across environments','A calendar and scheduling integration service that syncs meetings and events across AWS account teams'],correct:1,explanation:'AWS AppSync is a managed GraphQL service that simplifies app development by creating a flexible API to securely access, manipulate, and combine data from multiple sources.'},
{id:'ccp115',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Kendra?',options:['A customer service portal localized for Kenyan businesses with local pricing and AWS partner contacts','An intelligent enterprise search service that uses ML to surface accurate answers from internal content','A managed key-value store database optimized for high-throughput read-heavy workloads at scale','An encrypted private container registry for storing, scanning, and distributing Docker container images'],correct:1,explanation:'Amazon Kendra is an intelligent enterprise search service that uses natural language processing and ML to return accurate search results from your content repositories.'},
{id:'ccp116',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What does AWS Shield Advanced provide beyond Shield Standard?',options:['Nothing additional — AWS Shield Standard and Shield Advanced provide identical protection and features','24/7 DDoS Response Team access, detailed attack diagnostics, and cost protection against scaling charges from attacks','Only enhanced email alert notifications for detected DDoS attacks without any additional response capabilities','DDoS protection exclusively for on-premises infrastructure connected to AWS via Direct Connect'],correct:1,explanation:'AWS Shield Advanced adds DDoS Response Team support, detailed metrics, attack notifications, and cost protection for scaling charges caused by DDoS attacks.'},
{id:'ccp117',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon DocumentDB?',options:['A physical document storage and retrieval service for archiving paper records in climate-controlled facilities','A fully managed, MongoDB-compatible document database service designed for JSON workloads at scale','A file hosting service for storing and sharing PDF documents with teams through IAM-controlled access links','A real-time collaborative document editing platform similar to Google Docs integrated with AWS services'],correct:1,explanation:'Amazon DocumentDB is a fully managed MongoDB-compatible document database service, designed for JSON workloads at scale.'},
{id:'ccp118',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is the AWS Partner Network (APN)?',options:['A private social networking group for AWS employees to discuss internal product roadmaps and strategies','A global program of consulting and technology partners who help customers design and build on AWS','A peer-to-peer networking protocol used by EC2 instances to communicate directly without internet routing','A referral incentive program rewarding individual AWS customers for recommending AWS to new users'],correct:1,explanation:'The APN is a global ecosystem of partners—consultants, ISVs, and technology providers—that help customers design, architect, and build on AWS.'},
{id:'ccp119',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Neptune?',options:['A space exploration data ingestion service designed for processing satellite telemetry from NASA missions','A fully managed graph database supporting Property Graph and RDF for highly connected data workloads','A deep-sea acoustic monitoring service for ocean research organizations requiring specialized analytics','A high-performance computing cluster service for tightly-coupled scientific simulations and HPC workloads'],correct:1,explanation:'Amazon Neptune is a fully managed graph database that supports the Property Graph and RDF models, ideal for social networks, knowledge graphs, and fraud detection.'},
{id:'ccp120',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is the purpose of AWS Cost Anomaly Detection?',options:['An automated system for detecting and blocking fraudulent AWS account sign-ups and billing abuses','A service using ML to continuously monitor AWS costs and alert you when spending deviates from expected patterns','A security tool that detects unauthorized API access and unusual IAM activity through behavioral analysis','A performance monitoring system that identifies unexpected latency spikes and throughput degradation'],correct:1,explanation:'AWS Cost Anomaly Detection uses ML to identify unusual spending patterns, sending alerts when costs behave differently from expected norms.'},
{id:'ccp121',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon WorkSpaces?',options:['A platform for locating and reserving shared coworking spaces near AWS offices in major metro areas','A managed, persistent cloud desktop service providing virtual Windows or Linux desktops from any device','A project and task management tool for engineering teams tracking sprint velocity and backlog items','A collaborative code review environment integrated with Git for pull request reviews and pair programming'],correct:1,explanation:'Amazon WorkSpaces is a fully managed Desktop as a Service (DaaS) solution that gives users access to a cloud desktop from any device.'},
{id:'ccp122',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is the difference between authentication and authorization in IAM?',options:['Authentication and authorization are the same IAM concept described using two different terminology conventions','Authentication verifies who you are using credentials; authorization determines what resources you may access','Authentication governs billing and cost center assignment; authorization governs network configuration access','Authentication applies to human users only; authorization applies to services and application roles exclusively'],correct:1,explanation:'Authentication (who are you?) uses credentials to verify identity. Authorization (what can you do?) uses policies to determine allowed actions.'},
{id:'ccp123',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS Transit Gateway?',options:['A per-request fee collection service that meters internet traffic crossing AWS network boundaries','A cloud router that connects VPCs and on-premises networks through a central hub, simplifying topology','An internet-facing gateway that provides inbound and outbound internet access for all VPCs in a region','A billing gateway in AWS Marketplace for processing partner transactions and software subscription payments'],correct:1,explanation:'AWS Transit Gateway acts as a cloud router, connecting VPCs and on-premises networks through a central hub, simplifying network topology.'},
{id:'ccp124',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Quantum Ledger Database (QLDB)?',options:['A quantum computing database using qubits for probabilistic computation of financial models','A fully managed ledger database providing an immutable, cryptographically verifiable transaction log','An OLAP database designed for modeling quantum chemistry simulations and particle physics experiments','A usage tracking ledger that records AWS API calls, service activations, and billing events automatically'],correct:1,explanation:'Amazon QLDB is a fully managed ledger database with a transparent, immutable, and cryptographically verifiable transaction log.'},
{id:'ccp125',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is the purpose of AWS service quotas (formerly limits)?',options:['Restrictions placed on customers to prevent monopolization of popular AWS services in high-demand regions','Maximum values for resources and API requests that protect AWS infrastructure and prevent runaway consumption','Price caps that AWS applies to services to ensure customers never exceed a predetermined monthly budget','The maximum number of AWS Support cases a customer can open in a given calendar month or year'],correct:1,explanation:'Service quotas are limits on the maximum number of resources you can create and the rate of API calls, protecting both AWS infrastructure and your account.'},
{id:'ccp126',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon EventBridge?',options:['An event venue booking platform for scheduling and managing conference rooms and catering for AWS events','A serverless event bus that routes real-time events from AWS services, SaaS providers, and custom apps','A physical dashboard for monitoring live IoT sensor events and alerting on threshold breaches','A private connectivity service linking two Amazon VPCs within the same region without internet exposure'],correct:1,explanation:'Amazon EventBridge is a serverless event bus that makes it easier to build event-driven applications using events from AWS services, your apps, and SaaS.'},
{id:'ccp127',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is IAM Identity Center (formerly SSO)?',options:['A service for adding single sign-on capabilities to customer-facing web applications and SaaS products','A centralized service managing SSO access for employees across multiple AWS accounts and business apps','A two-factor authentication enforcement service requiring hardware tokens for all administrative logins','An identity theft monitoring service that alerts customers if their IAM credentials appear in public breaches'],correct:1,explanation:'AWS IAM Identity Center provides centralized SSO access to all your AWS accounts and business applications from one place.'},
{id:'ccp128',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon MemoryDB for Redis?',options:['A physical memory chip management utility for monitoring and replacing degraded RAM in server hardware','A Redis-compatible, durable, in-memory database with Multi-AZ persistence for ultra-fast application data','A memory profiling service for identifying and resolving memory leaks in running Lambda functions','A Redis documentation and community portal for learning advanced Redis data structures and patterns'],correct:1,explanation:'Amazon MemoryDB for Redis is a Redis-compatible, fully managed in-memory database that provides fast performance with Multi-AZ durability.'},
{id:'ccp129',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is "infrastructure as code" (IaC)?',options:['The practice of writing application code that runs natively on physical bare-metal servers without abstraction','Managing infrastructure by writing machine-readable code files rather than using manual console clicks','A hardware programming language for encoding logic directly into FPGA chips for low-latency networking','A metric-based monitoring approach that uses code to define thresholds and automate alert routing'],correct:1,explanation:'IaC manages infrastructure through code (like CloudFormation or Terraform), enabling version control, automation, and repeatable deployments.'},
{id:'ccp130',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS CodeBuild?',options:['A drag-and-drop website builder for creating and publishing static websites without writing HTML or CSS','A fully managed build service that compiles code, runs tests, and produces deployment artifacts automatically','A release orchestration service that sequences the stages of a complete CI/CD software delivery pipeline','A peer code review platform integrated with GitHub for discussing and approving pull requests collaboratively'],correct:1,explanation:'AWS CodeBuild is a fully managed continuous integration service that compiles source code, runs unit tests, and produces ready-to-deploy software packages.'},
{id:'ccp131',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is VPC Flow Logs?',options:['A log aggregating all DNS queries made from EC2 instances to any public or private hosted zone in Route 53','A feature that captures metadata about IP traffic flowing to and from network interfaces in your VPC','A comprehensive log of every AWS API call made across all services and regions in your account','A physical cable plant documentation service for recording rack locations and port connections in data centers'],correct:1,explanation:'VPC Flow Logs capture information about the IP traffic going to and from network interfaces in your VPC for security and troubleshooting.'},
{id:'ccp132',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS Outposts?',options:['Remote AWS field offices for in-person consulting and hands-on training at enterprise customer sites','Fully managed infrastructure that extends AWS services and APIs to on-premises locations as a hybrid solution','A surveillance and facility access monitoring service using AI-powered cameras at AWS data centers','Nodes in the AWS global network where partner traffic peers with AWS backbone connections for low latency'],correct:1,explanation:'AWS Outposts brings native AWS services, infrastructure, and operating models to on-premises and edge locations for hybrid cloud deployments.'},
{id:'ccp133',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is AWS Compute Optimizer?',options:['A physical tool for measuring and optimizing power efficiency in AWS server hardware components','A service that uses ML to recommend right-sized EC2 instances, Lambda configurations, and EBS volumes','A multi-cloud cost comparison tool that evaluates pricing across AWS, Azure, and Google Cloud simultaneously','A pricing estimator for calculating the cost of various compute configurations before committing to a purchase'],correct:1,explanation:'AWS Compute Optimizer uses ML to analyze usage metrics and recommend optimal compute resources to reduce costs and improve performance.'},
{id:'ccp134',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS Wavelength?',options:['A managed radio frequency spectrum allocation service for wireless IoT deployments in smart factories','AWS infrastructure embedded within 5G telecom provider networks for ultra-low-latency mobile edge computing','A light-based quantum networking standard for secure data transmission between AWS regions','A low-power wide-area wireless protocol for connecting battery-operated IoT sensors in remote environments'],correct:1,explanation:'AWS Wavelength embeds compute and storage within 5G networks, enabling developers to build ultra-low-latency applications for mobile edge computing.'},
{id:'ccp135',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What does TCO (Total Cost of Ownership) mean in cloud context?',options:['The total amount shown on your current AWS monthly bill including all services and data transfer charges','A full cost comparison including hardware, software, facilities, IT staff, and operations of on-premises versus cloud','The cumulative cost of all data transferred out of AWS to the internet across all regions and services','The total count of distinct AWS services actively used in your account during a given billing period'],correct:1,explanation:'TCO analysis compares the total costs of running on-premises (hardware, facilities, staff, software) vs cloud, often showing cloud has lower TCO.'},
{id:'ccp136',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Keyspaces?',options:['A managed key management service for creating and controlling symmetric and asymmetric encryption keys','A serverless, fully managed Apache Cassandra-compatible database for wide-column NoSQL workloads at scale','A shortcut management service for developers to create aliases for frequently used CLI commands','A key-value store optimized for gaming leaderboards with single-digit millisecond read and write performance'],correct:1,explanation:'Amazon Keyspaces is a serverless, Apache Cassandra-compatible database service that is scalable, available, and fully managed.'},
{id:'ccp137',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS Lake Formation?',options:['A civil engineering water resource management service used for irrigation and reservoir monitoring','A service that simplifies building a secure, governed data lake by automating ingestion, cataloging, and access control','An archival storage tier for data that is accessed less than once per year with multi-hour retrieval times','A professional development program for training new AWS engineers on foundational cloud architecture patterns'],correct:1,explanation:'AWS Lake Formation simplifies the creation of secure data lakes, handling the complex tasks of data ingestion, cataloging, security, and governance.'},
{id:'ccp138',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is an IAM Role?',options:['A job title used internally at AWS to designate the seniority level of a technical account manager','An IAM identity that can be assumed by services or users to receive temporary credentials for resource access','A permanent permission set attached directly to an IAM user and inherited by all applications they run','A physical designation on EC2 instances that routes them to a specific hardware tier in a data center'],correct:1,explanation:'IAM Roles provide temporary credentials and are assumed by EC2 instances, Lambda functions, or users to access AWS resources without embedding credentials.'},
{id:'ccp139',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Lookout for Metrics?',options:['A marketplace listing service where telescope vendors rent equipment for astronomical observation sessions','A service that uses ML to automatically detect anomalies in business and operational metrics without ML expertise','A real-time infrastructure health monitoring dashboard displaying availability and latency for AWS services','A KPI tracking spreadsheet template pre-loaded with AWS cost metrics for executive business reviews'],correct:1,explanation:'Amazon Lookout for Metrics automatically detects and diagnoses anomalies in business and operational metrics using ML, without requiring ML expertise.'},
{id:'ccp140',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is an S3 bucket policy?',options:['A lifecycle management policy that transitions S3 objects between storage classes based on age rules','A resource-based JSON policy attached to an S3 bucket that grants or denies access to the bucket and its objects','A cross-origin resource sharing configuration that controls which web domains can access S3 content','A replication configuration that automatically copies S3 objects to buckets in other regions or accounts'],correct:1,explanation:'An S3 bucket policy is a JSON-based resource policy that controls access to an S3 bucket and its objects, allowing or denying specific actions.'},
{id:'ccp141',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon CloudSearch?',options:['A legal discovery and evidence collection service for e-discovery workflows in regulated industries','A fully managed search service for building scalable, customizable search experiences for websites and apps','A cloud vendor comparison portal that indexes and ranks cloud providers by feature and pricing','A DNS search service that resolves custom domain names to internal AWS service endpoints in a VPC'],correct:1,explanation:'Amazon CloudSearch is a fully managed service that makes it easy to set up, manage, and scale a custom search solution.'},
{id:'ccp142',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Pinpoint?',options:['A high-precision GPS location tracking service for real-time fleet management and asset monitoring','A flexible communications service for sending targeted email, SMS, push notification, and voice campaigns','A geographic annotation tool for adding custom labels and markers to AWS region maps in documentation','A precision time protocol service ensuring sub-microsecond clock synchronization across EC2 instances'],correct:1,explanation:'Amazon Pinpoint is a flexible communications service for marketing, transactional, and bulk messaging campaigns via email, SMS, push, and voice channels.'},
{id:'ccp143',exams:['ccp'],domain:'Security & Compliance',difficulty:'easy',text:'What is AWS Certificate Manager (ACM)?',options:['A verification portal for validating the credentials of AWS certified partners and solution providers','A service that provisions, manages, and automatically renews SSL/TLS certificates for use with AWS services','A training and achievement tracking system for monitoring employee AWS certification progress and scores','A compliance management platform for mapping AWS service usage to industry certification requirements'],correct:1,explanation:'AWS ACM handles the complexity of creating, storing, and renewing SSL/TLS certificates for use with AWS services at no cost.'},
{id:'ccp144',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS CodeDeploy?',options:['A cold storage deployment service that archives infrequently accessed code artifacts to Amazon S3 Glacier','A fully managed deployment service that automates application rollouts to EC2, Lambda, and on-premises servers','A CDN-accelerated code distribution network for delivering large application binaries globally at low latency','A developer marketplace where teams publish reusable libraries and components for internal consumption'],correct:1,explanation:'AWS CodeDeploy automates code deployments to any instance—including EC2, Lambda, and on-premises—minimizing downtime during application updates.'},
{id:'ccp145',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is the difference between public and private subnets in a VPC?',options:['Public subnets include a monthly access fee; private subnets are included at no additional cost in a VPC','Public subnets have a route to an internet gateway enabling internet access; private subnets have no such route','Public subnets are for databases requiring high availability; private subnets are for web-facing compute tiers','Public and private subnets differ only in their naming convention; both route traffic identically in practice'],correct:1,explanation:'Public subnets route traffic to an internet gateway, enabling direct internet access. Private subnets have no internet gateway route, keeping resources isolated.'},
{id:'ccp146',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon Fraud Detector?',options:['A physical investigation service staffed by trained fraud examiners who review suspicious financial transactions','A fully managed ML service for detecting and scoring potentially fraudulent online activities in real time','A financial audit tool that reviews AWS billing records for billing errors and duplicate charges automatically','A biometric identity verification service that uses facial recognition to authenticate high-value transactions'],correct:1,explanation:'Amazon Fraud Detector uses ML to detect potentially fraudulent activities online, such as fake accounts and payment fraud, in real time.'},
{id:'ccp147',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is AWS Ground Station?',options:['An AWS managed weather monitoring station that tracks atmospheric conditions at data center locations','A fully managed service for controlling satellite communications and processing satellite data on AWS infrastructure','A GPS-based logistics optimization service for managing ground shipping routes and delivery scheduling','A tier of underground bunker data centers designed for maximum physical security and disaster resistance'],correct:1,explanation:'AWS Ground Station is a fully managed service for controlling satellite communications and processing satellite data using AWS global infrastructure.'},
{id:'ccp148',exams:['ccp'],domain:'Billing & Pricing',difficulty:'easy',text:'What is the purpose of Resource Tags in AWS billing?',options:['Labels physically attached to server rack equipment to identify hardware ownership and data classification levels','Key-value pairs applied to AWS resources for cost allocation and tracking spending by project, team, or environment','Security labels applied to IAM policies to mark their sensitivity level for governance and compliance reporting','Tags assigned to public IP addresses to document which team or application is responsible for network connectivity'],correct:1,explanation:'Resource tags are key-value pairs applied to AWS resources. Cost allocation tags help you track and allocate costs to specific projects or teams.'},
{id:'ccp149',exams:['ccp'],domain:'Technology',difficulty:'easy',text:'What is Amazon AppStream 2.0?',options:['A music and podcast streaming service integrated with Alexa for voice-controlled audio playback on Echo devices','A managed application streaming service that delivers desktop applications to any device through a web browser','A live-streaming video platform for broadcasting events, webinars, and product launches to global audiences','A software update distribution service that pushes application patches silently to end-user devices in bulk'],correct:1,explanation:'Amazon AppStream 2.0 streams desktop applications from AWS to any device with a web browser, without needing to install applications locally.'},
{id:'ccp150',exams:['ccp'],domain:'Cloud Concepts',difficulty:'easy',text:'What is the AWS Command Line Interface (CLI)?',options:['A physical hardware control panel installed in AWS data centers for managing power, cooling, and networking','A unified command-line tool for interacting with and automating AWS services through scripts and pipelines','A browser-based graphical management console for configuring and monitoring AWS resources visually','A support chat interface for submitting technical questions to AWS support engineers in real time'],correct:1,explanation:'The AWS CLI allows you to interact with AWS services using commands in your terminal, enabling automation and scripting of AWS operations.'},
{id:'ccp151',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company stores customer PII in S3 and must detect if any sensitive data is accidentally made public. Which service combination should they use?',options:['Amazon GuardDuty detects threats in account logs; AWS Shield defends against DDoS attacks at the network layer','Amazon Macie discovers and classifies sensitive data in S3; S3 Block Public Access prevents accidental public exposure','AWS Config evaluates resource compliance rules; Amazon Inspector scans for OS-level software vulnerabilities','AWS Trusted Advisor provides cost and security recommendations; AWS WAF filters malicious web requests'],correct:1,explanation:'Amazon Macie uses ML to discover and protect sensitive data (PII) in S3. Combined with S3 Block Public Access, it provides detection and prevention of accidental data exposure.'},
{id:'ccp152',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A startup wants to reduce their infrastructure costs. They have a predictable baseline load running 24/7 and occasional spikes. What is the MOST cost-effective EC2 purchasing strategy?',options:['On-Demand for all instances — full flexibility but no discount; highest per-hour cost for steady workloads','Reserved Instances for the predictable baseline (up to 72% savings) and Spot Instances for spikes (up to 90% off)','Spot Instances for all workloads — maximum discount but interruptions will affect the steady baseline too','Dedicated Hosts for all workloads — dedicated hardware for licensing compliance but highest per-instance cost'],correct:1,explanation:'Reserved Instances provide up to 72% savings for the steady, predictable baseline. Spot Instances (up to 90% off) handle spikes where interruption is tolerable—the combination maximizes savings.'},
{id:'ccp153',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A security audit finds that multiple IAM users share the same set of permissions needed for their job function. What is the BEST practice to manage this efficiently while maintaining least privilege?',options:['Grant each user AdministratorAccess so permission gaps never block productivity or cause support tickets','Create an IAM Group with the job-function policy attached, then add all relevant users to that group','Attach an identical policy directly to each individual user — changes require updating each user separately','Create one shared IAM user account for the team and distribute the credentials to avoid duplication'],correct:1,explanation:'IAM Groups let you assign permissions once at the group level. All members inherit those permissions, ensuring consistency and making changes easy—one edit affects all members.'},
{id:'ccp154',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A web application needs a database that automatically scales to handle millions of requests per second with single-digit millisecond latency and no schema management. Which service is the BEST fit?',options:['Amazon RDS for MySQL — managed relational database requiring predefined schema and complex query support','Amazon Redshift — a columnar data warehouse optimized for analytical queries, not high-throughput OLTP reads','Amazon DynamoDB — serverless NoSQL database scaling to any throughput with single-digit millisecond latency','Amazon Aurora PostgreSQL — high-performance relational database with schema management and ACID compliance'],correct:2,explanation:'DynamoDB is a serverless NoSQL database with automatic scaling to any throughput, single-digit millisecond performance, and no schema to manage—ideal for high-scale, low-latency use cases.'},
{id:'ccp155',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company runs several departments using AWS and wants each department to see only their own costs while a central team manages consolidated billing. Which AWS feature enables this?',options:['AWS Cost Explorer filters — allows ad hoc filtering but does not enforce per-department billing separation','IAM permission boundaries — limits what permissions IAM entities can have, not a billing allocation feature','AWS Organizations with Cost Allocation Tags — enables consolidated billing with per-department cost visibility','Separate AWS accounts without Organizations — eliminates shared benefits and requires manual billing aggregation'],correct:2,explanation:'AWS Organizations enables consolidated billing. Cost Allocation Tags let you label resources by department so each team can filter Cost Explorer to view only their own spending.'},
{id:'ccp156',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company is migrating from on-premises to AWS. They want to use the cloud\'s ability to automatically adjust resources during peak shopping seasons and scale down afterward. Which cloud characteristic does this describe?',options:['Fault tolerance — a system continues operating correctly even when individual components fail','Elasticity — the ability to automatically scale resources up during peak demand and release them when demand drops','Durability — the guarantee that stored data remains intact and uncorrupted over time','Portability — the ability to move workloads across cloud providers or between cloud and on-premises environments'],correct:1,explanation:'Elasticity is the ability to automatically acquire resources when demand rises and release them when demand falls—exactly what seasonal workload patterns require.'},
{id:'ccp157',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A developer accidentally committed AWS access keys to a public GitHub repository. What should be the IMMEDIATE first action?',options:['Set the GitHub repository to private immediately — access keys may already be cached by scrapers','Deactivate or delete the compromised IAM access keys immediately as the top priority action','Enable MFA on the IAM user — important for ongoing security but does not invalidate the exposed keys','Rotate the root user password — unrelated to the compromised programmatic access keys'],correct:1,explanation:'Exposed access keys must be deactivated or deleted immediately as the first priority. Once keys are in public repos they should be considered compromised—assume they have already been used maliciously.'},
{id:'ccp158',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'An application currently uses a self-managed MySQL database on EC2. The team wants to reduce operational overhead for backups, patching, and replication. Which migration path requires the LEAST operational overhead?',options:['Move MySQL to a larger EC2 instance — still requires manual backup, patching, and replication management','Migrate to Amazon RDS for MySQL — a managed service handling backups, patching, and Multi-AZ failover automatically','Migrate to Amazon Redshift — a data warehouse optimized for analytics, not transactional MySQL workloads','Migrate to Amazon DynamoDB — a NoSQL database incompatible with the existing relational MySQL schema'],correct:1,explanation:'Amazon RDS is a managed relational database service that handles backups, patching, Multi-AZ replication, and failover automatically—dramatically reducing operational overhead vs self-managed EC2.'},
{id:'ccp159',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A financial services company must demonstrate that their AWS environment meets PCI DSS compliance requirements to auditors. Which AWS service provides the compliance reports they need?',options:['AWS Trusted Advisor — provides best-practice recommendations but does not issue compliance attestation reports','AWS Artifact — a self-service portal for downloading AWS compliance reports including PCI DSS and SOC documents','Amazon Inspector — scans EC2 and containers for software vulnerabilities but does not produce compliance reports','AWS Security Hub — aggregates security findings but does not provide downloadable compliance attestation documents'],correct:1,explanation:'AWS Artifact is the self-service portal for AWS compliance documentation including SOC reports, PCI DSS Attestation of Compliance, ISO certifications, and other audit reports.'},
{id:'ccp160',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company wants to decouple a monolithic application into microservices. Producer services generate messages at peak times faster than consumers can process them. Which service should they use to absorb this burst?',options:['Amazon CloudFront — a CDN that caches and delivers content from edge locations, not a messaging service','AWS Lambda — a serverless compute service for running event-driven code, not a message queue','Amazon SQS — a managed queue that stores messages when producers outpace consumers, absorbing traffic bursts','Amazon CloudWatch — a monitoring service for collecting metrics and logs, not a message decoupling service'],correct:2,explanation:'Amazon SQS is a managed message queue that decouples producers and consumers. Messages are stored in the queue until consumers are ready, absorbing bursts without dropping messages.'},
{id:'ccp161',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'Under the AWS Shared Responsibility Model, who is responsible for patching the operating system on an Amazon EC2 instance?',options:['AWS is responsible for patching EC2 operating systems as part of managing the underlying infrastructure','The customer is responsible for patching the guest OS — EC2 gives full OS control to the customer','AWS applies OS patches but the customer must configure patch settings in Systems Manager','EC2 operating systems are patched automatically by AWS on a fixed maintenance schedule'],correct:1,explanation:'EC2 gives customers full control of the OS. The customer is responsible for patching and maintaining the guest OS. AWS handles the underlying hypervisor and physical hardware.'},
{id:'ccp162',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company wants to receive an alert when their monthly AWS bill is projected to exceed $10,000. Which service should they configure?',options:['AWS Cost Explorer with a saved report — shows historical trends but does not alert on projected overspend','AWS Budgets with a cost budget and alert threshold — sends email or SNS when actual or forecast costs exceed the limit','Amazon CloudWatch billing alarm — monitors actual charges but has fewer options than Budgets for forecasted spend','AWS Trusted Advisor cost check — reviews existing resources weekly but does not send real-time budget alerts'],correct:1,explanation:'AWS Budgets lets you set a monthly cost budget of $10,000 and sends an alert via email or SNS when actual or forecasted costs exceed that threshold.'},
{id:'ccp163',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company wants to host a static website (HTML, CSS, JavaScript) at the lowest possible cost with high availability globally. What is the MOST cost-effective solution?',options:['EC2 instances in multiple regions — high operational overhead and cost for a static site with no dynamic compute','Amazon S3 static website hosting combined with CloudFront for global edge caching and low-latency delivery','Amazon Lightsail multi-region — simpler than EC2 but still server-based, more expensive than S3 for static content','AWS Elastic Beanstalk with auto scaling — designed for dynamic server-side applications, not static file hosting'],correct:1,explanation:'S3 static website hosting is extremely cheap (pay per GB stored and requests). Adding CloudFront distributes content via edge locations worldwide for low latency—the most cost-effective global static site approach.'},
{id:'ccp164',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company needs to ensure that no resources in any of their AWS accounts can be deployed outside of the us-east-1 and eu-west-1 regions. What is the MOST effective way to enforce this at scale?',options:['Rely on developer training and documentation to encourage use of approved regions voluntarily','Apply IAM user policies per user restricting region access — difficult to maintain at scale and bypassable','Apply a Service Control Policy (SCP) via AWS Organizations — enforces region restriction on all accounts without override','Deploy AWS Config rules in each account — detects violations after the fact but does not prevent deployments'],correct:2,explanation:'SCPs in AWS Organizations apply to all accounts and OUs, enforcing guardrails that cannot be overridden by any account administrator—the most scalable way to restrict regions organization-wide.'},
{id:'ccp165',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company is evaluating moving to AWS. They currently spend $2M/year on data center hardware, $500K on facilities/power, and $300K on IT staff for infrastructure. Their estimated AWS bill would be $1.4M/year. What concept does this comparison represent?',options:['ROI calculation — measures the financial return on an investment relative to its cost over time','TCO (Total Cost of Ownership) analysis — compares all costs of on-premises vs cloud including hardware, facilities, and staff','Break-even analysis — determines the point at which total cloud costs equal the total on-premises costs','Opportunity cost analysis — quantifies what must be foregone when choosing one investment over another'],correct:1,explanation:'TCO analysis compares the full on-premises costs (hardware, facilities, power, staff) against cloud costs. In this case, $2.8M on-premises vs $1.4M in the cloud—TCO shows cloud is significantly cheaper.'},
{id:'ccp166',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'An application needs to process images uploaded to S3 and store metadata in a database within seconds of upload. What is the MOST serverless and cost-effective architecture?',options:['EC2 worker that polls S3 every minute — introduces polling delay and wastes compute when there are no uploads','S3 Event Notification triggering Lambda which processes the image and writes metadata to DynamoDB','EC2 Auto Scaling Group writing to RDS — server-based, requires polling, and incurs idle instance costs','Amazon Kinesis Data Streams feeding EC2 — designed for high-volume streaming, not per-file event triggers'],correct:1,explanation:'S3 event notifications trigger Lambda automatically on upload—no polling needed. Lambda processes the image and writes to DynamoDB. This is fully serverless, event-driven, and you pay only for actual executions.'},
{id:'ccp167',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company uses AWS and their on-premises Active Directory for identity management. They want employees to use their existing corporate credentials to access AWS without creating separate IAM users. Which solution achieves this?',options:['Create IAM users mirroring all Active Directory accounts — creates duplicate identity management overhead','Use AWS IAM Identity Center with Active Directory as the identity source — enables SSO with existing AD credentials','Share the AWS root user credentials with all employees — a critical security risk, never recommended','Use Amazon Cognito for corporate identity federation — designed for app user authentication, not employee AWS access'],correct:1,explanation:'IAM Identity Center (formerly SSO) integrates with existing identity providers including Active Directory, allowing employees to use corporate credentials for SSO access to AWS accounts and applications.'},
{id:'ccp168',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company has 3 AWS accounts using different amounts of data transfer, S3 storage, and EC2 hours. They consolidate under AWS Organizations. How might their overall bill change?',options:['Bills will always increase due to the management overhead added by AWS Organizations','Bills may decrease because combined usage across all accounts can qualify for volume pricing tiers','Bills will stay exactly the same since Organizations simply consolidates invoices without changing pricing','Bills will increase because AWS Organizations charges a premium fee on top of each member account\'s usage'],correct:1,explanation:'Consolidated billing combines usage across all member accounts. Higher aggregate usage may qualify for volume pricing tiers (e.g., S3 pricing decreases per-GB as total usage increases), potentially lowering the total bill.'},
{id:'ccp169',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company wants to run a batch machine learning training job that takes 6 hours, can tolerate interruption, and needs to minimize cost. Which EC2 purchasing option is BEST?',options:['On-Demand with checkpointing — safe from interruption but highest per-hour cost for a 6-hour job','Reserved Instance (1-year) — discounted for steady long-running workloads, not appropriate for a single batch job','Spot Instance with checkpointing — up to 90% savings over On-Demand; interruptions are handled by restarting from checkpoint','Dedicated Host — provides physical isolation for licensing compliance but has the highest overall cost'],correct:2,explanation:'Spot Instances offer up to 90% savings over On-Demand. For a 6-hour batch ML job that can checkpoint and resume if interrupted, Spot is the most cost-effective choice.'},
{id:'ccp170',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company\'s application in us-east-1 must continue serving traffic even if an entire AWS Region becomes unavailable. Which architectural approach achieves this?',options:['Deploy EC2 and RDS across multiple Availability Zones in us-east-1 — protects against AZ failure, not full region failure','Deploy to a second AWS Region and use Route 53 failover routing to redirect traffic if us-east-1 is unavailable','Enable Multi-AZ on the RDS database — protects the data tier from AZ failure but leaves compute in a single region','Use CloudFront to cache responses — edge caching reduces origin load but does not survive an origin region outage'],correct:1,explanation:'Multi-AZ protects against AZ failure but not full Region failure. To survive a Region outage, you must deploy to a second Region and use Route 53 failover routing to redirect traffic automatically.'},
{id:'ccp171',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'Which statement BEST describes what AWS CloudTrail provides that Amazon CloudWatch does NOT?',options:['CloudTrail monitors application performance metrics and response times; CloudWatch does not provide this capability','CloudTrail records who made AWS API calls, what was called, and when; CloudWatch monitors performance metrics and alarms','CloudTrail captures VPC Flow Logs and network traffic; CloudWatch captures only API call information','Both services do the same thing — they are different names for the same AWS logging and monitoring platform'],correct:1,explanation:'CloudTrail is the audit/compliance tool—it logs every API call (who, what, when, from where) for governance and forensics. CloudWatch is the operational monitoring tool—it collects metrics, logs, and triggers alarms on performance data.'},
{id:'ccp172',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company needs to migrate 80TB of on-premises data to S3. Their internet connection is 100 Mbps shared with production traffic. Uploading over the internet would take months and impact operations. What is the BEST solution?',options:['Compress the data and schedule uploads during off-hours — still weeks of transfer time degrading shared bandwidth','Use AWS Direct Connect — a dedicated circuit, but setup takes weeks and doesn\'t solve the 80TB volume problem','Order an AWS Snowball Edge device — load data locally and ship to AWS for fast, offline large-scale transfers','Use AWS DataSync over the existing 100 Mbps connection — still weeks of transfer competing with production traffic'],correct:2,explanation:'80TB over a 100Mbps connection (even unshared) would take weeks and degrade production. AWS Snowball Edge ships a physical device you load data onto locally and ship to AWS—much faster for large offline transfers.'},
{id:'ccp173',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company wants to use AWS services but must keep certain sensitive workloads on-premises due to data sovereignty regulations, while integrating them with cloud workloads. Which deployment model does this describe?',options:['Public cloud only — all workloads run on shared AWS infrastructure with no on-premises component','Private cloud only — all workloads run on on-premises infrastructure with no cloud integration','Hybrid cloud — on-premises and cloud resources are integrated, allowing regulated data to stay on-premises','Multi-cloud — workloads are distributed across multiple public cloud providers for redundancy or cost reasons'],correct:2,explanation:'A hybrid cloud connects on-premises infrastructure with cloud services, allowing regulated/sensitive workloads to stay on-premises while other workloads use cloud services—all integrated together.'},
{id:'ccp174',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company wants to automatically remediate non-compliant S3 buckets that have public access enabled. Which AWS services should they combine?',options:['Amazon Macie classifies sensitive data in S3; Amazon Inspector scans for software vulnerabilities on EC2','AWS Config rules detect non-compliant S3 configurations; Systems Manager Automation runbooks remediate them automatically','AWS Trusted Advisor flags publicly accessible S3 buckets; AWS Lambda can be triggered manually to fix them','Amazon GuardDuty detects threats in account activity; AWS WAF filters malicious HTTP requests at the application layer'],correct:1,explanation:'AWS Config rules continuously evaluate S3 bucket configurations. When a rule detects a non-compliant resource, it can trigger Systems Manager Automation runbooks to automatically remediate the issue (e.g., block public access).'},
{id:'ccp175',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company pays for EC2 instances in several sizes (t3.medium, m5.large, c5.xlarge) across multiple services. They want maximum pricing flexibility without being locked to specific instance types or sizes. Which commitment option provides this?',options:['Standard Reserved Instances — locked to a specific instance type, size, region, OS, and tenancy for 1 or 3 years','Convertible Reserved Instances — can be exchanged for different attributes but still tied to a specific region','Compute Savings Plans — apply automatically to any EC2 family, size, region, OS, tenancy, plus Lambda and Fargate','EC2 Instance Savings Plans — apply to one instance family in one region only; do not cover Lambda or Fargate'],correct:2,explanation:'Compute Savings Plans apply automatically to any EC2 instance family, size, region, OS, and tenancy—plus Lambda and Fargate. They offer up to 66% savings with maximum flexibility, unlike Reserved Instances which lock you to specific configurations.'},
{id:'ccp176',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company\'s application must store session state and share it across multiple EC2 instances behind a load balancer, so any instance can serve any user request. Which approach is BEST?',options:['Store session data on each EC2 instance\'s local disk — sessions are lost if the instance is replaced or fails','Use EC2 instance store volumes for session data — ephemeral storage that is wiped when the instance stops','Store sessions in Amazon ElastiCache (Redis) — all instances share the same session store, surviving instance replacements','Attach EBS volumes to all instances for session storage — EBS volumes cannot be shared across multiple running instances'],correct:2,explanation:'Storing sessions in ElastiCache Redis makes session data available to all EC2 instances equally. Local disk or instance store is lost when an instance is replaced. EBS cannot be shared across multiple running instances.'},
{id:'ccp177',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'Which of the following is SOLELY the responsibility of AWS under the Shared Responsibility Model?',options:['Configuring IAM user passwords and MFA devices — the customer manages all identity and access configurations','Patching the operating system on customer EC2 instances — customers retain full control of their guest OS','Physical security of AWS data center facilities — AWS controls all physical access, cameras, and environmental controls','Encrypting customer data stored in S3 — customers choose and manage their encryption strategy and keys'],correct:2,explanation:'Physical security of data centers (locks, guards, cameras, environmental controls) is entirely AWS\'s responsibility—customers have no access or control over physical infrastructure. All other options are customer responsibilities.'},
{id:'ccp178',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company wants to send automated email and SMS notifications when an Auto Scaling event occurs. Which AWS service should receive the Auto Scaling notification and fan it out to multiple subscribers?',options:['Amazon SQS — a queue that buffers messages; it does not natively push to email or SMS endpoints','Amazon SNS — a pub/sub service that fans out Auto Scaling notifications to email, SMS, Lambda, and SQS simultaneously','AWS Lambda — can process events but requires an additional trigger mechanism to receive Auto Scaling events','Amazon EventBridge — can route events to targets but SNS is the simpler native integration for multi-protocol fan-out'],correct:1,explanation:'Amazon SNS is a pub/sub messaging service. Auto Scaling can publish events to an SNS topic, which then fans out to multiple subscriptions—email endpoints, SMS, Lambda functions, SQS queues—simultaneously.'},
{id:'ccp179',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company needs to store database passwords and API keys used by their applications, with automatic rotation every 30 days and audit logs of every access. Which service is purpose-built for this?',options:['AWS KMS — manages cryptographic keys for encryption but does not store or rotate application secrets','AWS Systems Manager Parameter Store (Standard) — stores configuration data but lacks built-in automatic secret rotation','AWS Secrets Manager — purpose-built for secrets storage with automatic rotation, audit logging, and fine-grained access','Amazon S3 with server-side encryption — object storage for files; not designed for secret management or rotation'],correct:2,explanation:'AWS Secrets Manager is purpose-built for secrets management with built-in automatic rotation for supported services, fine-grained access control, and integration with CloudTrail for access auditing.'},
{id:'ccp180',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company is choosing between AWS Support plans. They need access to AWS Support API, a full set of Trusted Advisor checks, and a response time under 1 hour for production system failures. Which is the MINIMUM plan that meets all these requirements?',options:['Basic Support — provides documentation, forums, and billing support only; no technical support included','Developer Support — email support during business hours with 12-hour response time; no phone access or full Trusted Advisor','Business Support — all Trusted Advisor checks, AWS Support API, and 1-hour response for production impairments','Enterprise Support — dedicated TAM, 15-minute response for business-critical outages, and concierge support'],correct:2,explanation:'Business Support provides: access to all Trusted Advisor checks, AWS Support API access, and 1-hour response SLA for production system impairments. Developer only provides 12-hour business hours response; Basic has no technical support.'},
{id:'ccp181',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company runs hundreds of AWS accounts across multiple business units. The security team needs to enforce a rule that prevents ANY account from disabling AWS CloudTrail, even account administrators. Which service and feature achieves this?',options:['Deploy an AWS Config rule to every account — detects violations after the fact but cannot prevent administrators from stopping CloudTrail','Apply IAM permission boundaries to admin roles — scopes max permissions but cannot restrict account root users','Apply a Service Control Policy (SCP) in AWS Organizations denying cloudtrail:StopLogging — blocks all principals including root','Enable AWS CloudTrail log file validation in each account — detects tampering with log files but does not prevent disabling'],correct:2,explanation:'SCPs in AWS Organizations are the only mechanism that can restrict even account root users and administrators. An SCP denying cloudtrail:StopLogging applies to all principals in all member accounts and cannot be overridden at the account level.'},
{id:'ccp182',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'An e-commerce company experiences traffic spikes every Friday at 8 PM that are 10x normal load, lasting about 2 hours. The rest of the week is steady and predictable. Which purchasing strategy minimizes cost while ensuring capacity?',options:['Use all Spot Instances — cheapest but risky; AWS can reclaim capacity during the Friday peak causing customer-facing failures','Purchase Reserved Instances for 100% of peak capacity — wastes money paying for peak capacity 95% of the week','Use Reserved Instances for the steady baseline plus On-Demand or Scheduled RIs for the predictable Friday spikes','Use On-Demand for everything — no wasted capacity but misses up to 72% savings on the steady baseline workload'],correct:2,explanation:'Reserved Instances cover the steady baseline at up to 72% savings. The predictable Friday spike is best handled with Scheduled Reserved Instances (or On-Demand if scheduled RIs are unavailable) — Spot is too risky for customer-facing spikes since AWS can reclaim them.'},
{id:'ccp183',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A solutions architect reviews a workload where a single EC2 instance runs both the web server and database. A hardware failure would cause complete downtime. Which Well-Architected pillar is MOST violated, and what is the PRIMARY fix?',options:['Cost Optimization — consolidate the web server and database onto the fewest possible instances to reduce spend','Performance Efficiency — provision a larger instance type to handle both web and database workloads more efficiently','Reliability — separate application tiers and deploy each across multiple AZs to eliminate the single point of failure','Operational Excellence — add CloudWatch dashboards and alarms to detect the failure and alert the on-call team'],correct:2,explanation:'Reliability requires eliminating single points of failure. Separating the web tier from the database tier and deploying each across multiple AZs (Auto Scaling Group + RDS Multi-AZ) directly addresses the SPOF risk described.'},
{id:'ccp184',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company wants to reduce their AWS bill. AWS Compute Optimizer recommends downsizing several EC2 instances, and Cost Explorer shows $3,000/month on NAT Gateway data processing charges. Which TWO actions would reduce costs? (Choose the best single answer that captures both.)',options:['Purchase Reserved Instances for compute and enable S3 Transfer Acceleration for faster object uploads','Right-size EC2 instances per Compute Optimizer recommendations and route S3 traffic via VPC Gateway Endpoints (free) instead of NAT Gateway','Enable AWS Cost and Usage Report and configure Budgets alerts for spending threshold notifications','Move all instances to Spot and purchase Compute Savings Plans for the remainder of the compute workload'],correct:1,explanation:'Right-sizing EC2 per Compute Optimizer reduces compute spend. S3 traffic routed through a free VPC Gateway Endpoint bypasses the NAT Gateway entirely, eliminating those data processing charges. These are two of the most common quick wins Cost Explorer surfaces.'},
{id:'ccp185',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company\'s compliance framework requires that all data stored in S3 must be encrypted, and encryption must be enforced regardless of how objects are uploaded. Which S3 feature enforces this server-side?',options:['S3 Versioning — preserves previous object versions but does not enforce encryption on new uploads','S3 Default Encryption (SSE-S3 or SSE-KMS) with a bucket policy denying unencrypted PutObject requests','S3 Object Lock — prevents object deletion or overwriting for compliance; does not enforce upload encryption','S3 Transfer Acceleration — speeds up uploads using CloudFront edge locations; has no encryption enforcement role'],correct:1,explanation:'S3 Default Encryption ensures all new objects are encrypted at rest. Adding a bucket policy with a condition denying s3:PutObject when x-amz-server-side-encryption is absent ensures no unencrypted object can be uploaded, enforcing compliance programmatically.'},
{id:'ccp186',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A startup is building a multi-tenant SaaS app on AWS. Each tenant\'s data must be completely isolated. The team wants to use a single AWS account for cost simplicity. Which approach provides the STRONGEST data isolation without separate accounts?',options:['Store all tenants in one DynamoDB table using tenant ID as partition key — a code bug could expose cross-tenant data','Use separate S3 buckets per tenant with enforcing bucket policies and separate RDS schemas per tenant for strong isolation','Use a single RDS database with row-level tenant ID columns — relies entirely on application logic to prevent data leaks','Deploy one Lambda function per tenant — provides compute isolation but does not address shared data store isolation'],correct:1,explanation:'Separate S3 buckets with bucket policies enforcing tenant-specific access, combined with separate RDS schemas (or databases), provides strong logical isolation within a single account. Row-level isolation in a shared table is weaker — a misconfigured query could expose cross-tenant data.'},
{id:'ccp187',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company is planning to migrate from on-premises to AWS using a "lift and shift" approach. Which migration strategy does this describe, and what is its PRIMARY characteristic?',options:['Re-architect — redesign and rebuild the application using cloud-native microservices and managed services','Re-platform — migrate to managed services like RDS or Elastic Beanstalk with targeted optimizations','Rehost — move applications to EC2 and RDS with minimal changes; the fastest path but no cloud-native optimization','Retire — decommission applications that are no longer needed rather than migrating them to the cloud'],correct:2,explanation:'"Lift and shift" is Rehost: move VMs and databases to EC2 and RDS with minimal changes. It is the fastest migration path with least risk, but doesn\'t take full advantage of cloud-native features. The 6 Rs of migration are Rehost, Replatform, Repurchase, Re-architect, Retire, and Retain.'},
{id:'ccp188',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company recently suffered a security incident where an EC2 instance was compromised and used to make unauthorized API calls. Which TWO services would have provided the EARLIEST detection? (Select the best combined answer.)',options:['AWS WAF and Amazon Inspector — WAF filters web traffic; Inspector scans for vulnerabilities; neither detects compromised instance behavior','Amazon GuardDuty (detects unusual API activity in real time) and AWS CloudTrail (provides the API audit record for forensics)','AWS Config and Amazon Macie — Config tracks configuration changes; Macie classifies S3 data; neither detects compromised instance API abuse','AWS Shield and AWS Trusted Advisor — Shield blocks DDoS; Trusted Advisor reviews best practices; neither detects credential misuse'],correct:1,explanation:'GuardDuty continuously analyzes CloudTrail, VPC Flow Logs, and DNS logs using ML to detect unusual API calls and credential abuse — it would alert on the anomalous behavior. CloudTrail provides the forensic record of exactly which API calls were made, by whom, from where, enabling post-incident investigation.'},
{id:'ccp189',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company runs a stateful application where users must always reach the same EC2 instance during their session. They are deploying an Elastic Load Balancer. Which ELB feature and type should they use?',options:['Network Load Balancer with cross-zone load balancing — NLB operates at Layer 4 (TCP) and does not support session affinity by cookie','Application Load Balancer with sticky sessions — uses a cookie to route a client to the same target for the session duration','Classic Load Balancer with health checks only — older generation without advanced routing or sticky session capabilities','Gateway Load Balancer with target groups — designed for deploying third-party network appliances, not application load balancing'],correct:1,explanation:'Sticky sessions (session affinity) on an Application Load Balancer use a cookie to route a client\'s requests to the same target for the duration of the session. ALB operates at Layer 7 and supports sticky sessions natively — the right tool for HTTP/HTTPS stateful applications.'},
{id:'ccp190',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company has a 3-year commitment and wants maximum EC2 savings. They run a mix of instance families and sizes across multiple regions and also use Lambda. Which savings option provides the MOST flexibility across all these services?',options:['Standard Reserved Instances in each region — locked to specific instance family, size, and region; does not cover Lambda','Convertible Reserved Instances — can exchange for different instance attributes but do not apply to Lambda or Fargate','Compute Savings Plans — automatically apply to any EC2 family, size, region, OS, tenancy, plus Lambda and Fargate usage','EC2 Instance Savings Plans — limited to one instance family in one region; do not cover Lambda or Fargate workloads'],correct:2,explanation:'Compute Savings Plans apply automatically across EC2 (any family, size, region, OS, tenancy), AWS Lambda, and AWS Fargate — the broadest coverage. EC2 Instance Savings Plans are limited to one instance family per region. Convertible RIs are flexible but don\'t cover Lambda or Fargate.'},
{id:'ccp191',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company needs to run a high-performance computing (HPC) simulation that requires extremely low latency between nodes and high bandwidth networking. Which EC2 feature should they enable?',options:['Multi-AZ deployment — distributes instances across Availability Zones for fault tolerance, not low-latency inter-node communication','Enhanced Networking with Elastic Fabric Adapter (EFA) — OS-bypass networking for ultra-low latency HPC tightly-coupled workloads','EC2 Placement Groups (Spread strategy) — maximizes fault tolerance by placing instances on separate hardware, not for HPC performance','Auto Scaling with predictive scaling — adjusts capacity based on forecasted demand; does not improve inter-node networking'],correct:1,explanation:'Elastic Fabric Adapter (EFA) enables ultra-low latency OS-bypass networking between EC2 instances, purpose-built for HPC tightly-coupled workloads. Cluster Placement Groups co-locate instances physically for low latency. Spread placement is for fault tolerance, not performance.'},
{id:'ccp192',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company has an on-premises application that calls an AWS API millions of times per day. Network latency to the public AWS endpoint is causing performance issues. What are the TWO best options to reduce latency? (Select the best combined answer.)',options:['Increase ISP bandwidth and compress API payloads — reduces data size but does not eliminate public internet latency','Use AWS Direct Connect for a dedicated private connection, or move the application to EC2 in the same region as the API','Enable AWS Shield Advanced — provides DDoS protection and global threat mitigation; does not reduce API latency','Use Amazon CloudFront — effective for caching static and idempotent GET responses but not dynamic write-heavy API calls'],correct:1,explanation:'Direct Connect provides a dedicated private circuit to AWS bypassing the public internet, drastically reducing latency and increasing throughput. Moving the application to EC2 in the same region as the API eliminates the on-premises round-trip entirely. CloudFront can cache idempotent GET responses but doesn\'t help with dynamic write-heavy API calls.'},
{id:'ccp193',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A developer is building a mobile app that needs to access a user\'s photos stored in S3. The app authenticates users with Google Sign-In. Which AWS service allows the app to exchange the Google token for temporary AWS credentials to access S3?',options:['AWS IAM users with long-term access keys — embedding static credentials in mobile apps is a security anti-pattern','Amazon Cognito Identity Pools — exchanges Google tokens for temporary, scoped AWS credentials via STS for direct resource access','AWS IAM Identity Center — designed for employee SSO to AWS accounts and business applications, not end-user mobile authentication','AWS Directory Service — extends Active Directory to AWS; not designed for consumer mobile app authentication flows'],correct:1,explanation:'Amazon Cognito Identity Pools allow users to authenticate with external identity providers (Google, Facebook, Apple, SAML) and receive temporary, scoped AWS credentials via STS. This is the standard pattern for granting mobile/web app users direct access to AWS resources without managing IAM users.'},
{id:'ccp194',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'An application writes 1,000 records per second to a DynamoDB table. After several months, read performance on older records degrades and costs increase. The team realizes they only need fast access to the last 90 days of data, and older records can be archived cheaply. Which DynamoDB feature automates this lifecycle?',options:['DynamoDB Streams — captures item-level changes for event-driven processing; does not expire or delete old items automatically','DynamoDB Global Tables — replicates data across multiple AWS regions for multi-region active-active access patterns','DynamoDB Time to Live (TTL) — automatically deletes items at a configured expiration timestamp with optional S3 export via Streams','DynamoDB DAX — an in-memory accelerator providing microsecond read latency; does not manage data lifecycle or deletion'],correct:2,explanation:'DynamoDB TTL lets you set an expiration timestamp per item. When items expire, DynamoDB deletes them automatically at no extra cost. Combining TTL with DynamoDB Streams → Lambda → S3 (or DynamoDB export to S3) archives data before deletion, keeping the table lean and costs low.'},
{id:'ccp195',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company notices that data transfer costs are a significant portion of their AWS bill. They serve users globally from an S3 bucket in us-east-1. What is the MOST cost-effective architectural change to reduce data transfer costs?',options:['Move data to S3 Glacier — dramatically increases retrieval latency; not suitable for frequently accessed content','Enable S3 Transfer Acceleration — speeds up uploads to S3 using CloudFront edges; does not reduce outbound data transfer costs','Add CloudFront in front of S3 — caches content at edge locations near users, reducing origin data transfer and lowering per-GB cost','Upgrade to a larger EC2 instance — does not reduce data transfer costs; charges are based on bytes transferred, not instance size'],correct:2,explanation:'CloudFront caches S3 content at edge locations. Subsequent requests are served from the edge without fetching from the origin, dramatically reducing S3 outbound data transfer charges (CloudFront\'s per-GB rate to end users is lower than S3\'s, and cache hits eliminate origin transfer altogether).'},
{id:'ccp196',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company is migrating their Oracle data warehouse to AWS. They want a cloud-native managed solution optimized for analytical queries (OLAP) across petabytes of data. Which service is the BEST fit?',options:['Amazon RDS for Oracle — managed OLTP database for transactional workloads; not optimized for petabyte-scale analytics','Amazon DynamoDB — serverless NoSQL key-value database; not designed for complex SQL analytical queries','Amazon Redshift — fully managed columnar data warehouse using MPP, purpose-built for petabyte-scale OLAP analytics','Amazon Aurora PostgreSQL — high-performance relational database; optimized for OLTP transactions, not data warehouse analytics'],correct:2,explanation:'Amazon Redshift is a fully managed, petabyte-scale cloud data warehouse optimized for OLAP analytical workloads with columnar storage and massively parallel processing. RDS and Aurora are OLTP databases. DynamoDB is a NoSQL key-value store — none are designed for petabyte-scale analytics.'},
{id:'ccp197',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company must ensure that EC2 instances in a private subnet can download software updates from the internet but cannot accept any inbound connections from the internet. Which component achieves this?',options:['Internet Gateway attached to the private subnet — gives instances direct inbound and outbound internet access, defeating isolation','VPC Peering connection — connects two VPCs for private communication; does not provide internet access for private subnets','NAT Gateway deployed in a public subnet — allows private subnet instances to initiate outbound connections while blocking all inbound','Elastic IP addresses on private instances — assigns public IPs which would expose instances directly to inbound internet traffic'],correct:2,explanation:'A NAT Gateway allows instances in private subnets to initiate outbound internet connections (for updates, patches) while blocking all unsolicited inbound traffic. It sits in a public subnet; private subnet route tables point 0.0.0.0/0 to the NAT Gateway, not an Internet Gateway.'},
{id:'ccp198',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company wants to test a new version of their application alongside the current version, gradually shifting traffic from v1 to v2 while monitoring error rates. Which deployment strategy does this describe?',options:['Blue/green deployment — provisions a parallel environment and switches 100% of traffic at cutover with instant rollback capability','Canary deployment — routes a small percentage of traffic to the new version, monitors metrics, then gradually shifts more traffic','In-place deployment — updates all instances simultaneously with no parallel environment and high risk of full-fleet failures','Disaster recovery — runs a secondary environment in a different region for failover; not a strategy for controlled version rollout'],correct:1,explanation:'A canary deployment routes a small initial percentage of traffic (e.g., 5%) to the new version, monitors metrics, and progressively increases traffic if healthy. Blue/green cuts over 100% at once (with fast rollback). In-place updates all instances together — high risk. AWS CodeDeploy, ALB weighted target groups, and Route 53 weighted routing all support canary patterns.'},
{id:'ccp199',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A healthcare company needs to store medical imaging files (very large objects, up to 5 GB each). They need low-latency access and the objects are accessed frequently in the first 30 days, rarely after 6 months, and almost never after 2 years. Which S3 feature automatically optimizes storage costs for this pattern?',options:['S3 Lifecycle policy: Standard for 30 days → Standard-IA after 30 days → Glacier after 180 days, matching the access pattern exactly','S3 Versioning with MFA Delete — preserves object versions and prevents accidental deletion; does not automate storage tiering','S3 Block Public Access — prevents public exposure of objects in the bucket; has no effect on storage class or cost optimization','S3 Requester Pays — shifts data transfer costs to the downloading party; does not change storage class or object lifecycle'],correct:0,explanation:'S3 Lifecycle rules automate tiering based on object age. Standard (frequent access) → Standard-IA after 30 days (lower storage cost, retrieval fee) → S3 Glacier after 180 days (archive, very low cost) perfectly matches the described access pattern and requires no application changes.'},
{id:'ccp200',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'After enabling Cost Allocation Tags and reviewing Cost Explorer, a company discovers that 40% of their monthly spend comes from EC2 instances tagged "environment: dev" that run 24/7. These dev instances are only used 8 hours a day, 5 days a week. What is the MOST cost-effective solution?',options:['Move dev instances to Spot — saves money but risks interruptions that disrupt developer workflows during working hours','Purchase Reserved Instances for dev — wasteful since dev instances are only used 24% of the time (40 hours/week)','Use AWS Instance Scheduler or a Lambda function to automatically stop dev instances outside of working hours','Migrate dev workloads to AWS Fargate — requires containerizing all workloads and may not support all dev tool requirements'],correct:2,explanation:'Dev instances used only 40 hours/week (24%) don\'t justify Reserved Instances or Spot complexity. Automatically stopping them outside working hours (using AWS Instance Scheduler, a Lambda cron, or EC2 instance start/stop automation) eliminates ~76% of their runtime costs immediately.'},
{id:'ccp201',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company stores credit card data and must comply with PCI DSS. They want to avoid storing raw card numbers at all. Which AWS service allows applications to process payments while replacing sensitive card data with a non-sensitive token?',options:['AWS KMS encryption — encrypts data at rest but the application still processes and briefly holds the raw card number','Amazon Macie data classification — discovers and classifies sensitive data in S3 but does not tokenize or mask it','AWS Payment Cryptography tokenization — replaces the raw card number (PAN) with a non-sensitive token, removing it from application scope','AWS Secrets Manager — stores and rotates credentials and API keys; not designed for payment card tokenization'],correct:2,explanation:'AWS Payment Cryptography provides payment-grade tokenization and cryptography that replaces sensitive card data (PAN) with a non-sensitive token, reducing PCI DSS scope. KMS encrypts data but the application still handles the raw number. Macie discovers sensitive data but doesn\'t tokenize it.'},
{id:'ccp202',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company needs a database for a social network application that stores user relationships as a highly connected graph (friends, followers, mutual connections). Queries must traverse many relationship hops efficiently. Which database type and AWS service is BEST suited?',options:['Amazon RDS (relational) — uses complex multi-table JOINs which degrade exponentially as relationship depth increases','Amazon DynamoDB (NoSQL) — can model relationships with adjacency lists but traversal requires multiple serial read operations','Amazon Neptune (graph database) — native graph traversal engine designed to follow millions of relationships at millisecond latency','Amazon Redshift (data warehouse) — columnar OLAP database for analytical queries on structured data, not real-time graph traversal'],correct:2,explanation:'Amazon Neptune is a purpose-built graph database supporting Property Graph (Gremlin) and RDF (SPARQL) models. Graph databases traverse relationships natively without expensive JOINs. Social networks, knowledge graphs, fraud detection, and recommendation engines are Neptune\'s primary use cases.'},
{id:'ccp203',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company is designing their AWS network architecture. They want to minimize the blast radius if one part of the system is compromised, applying network-level isolation between application tiers. Which design principle does this represent?',options:['Elasticity — the ability to automatically scale compute resources up or down in response to changing demand levels','Defense in depth using network segmentation — applying multiple isolation layers to limit lateral movement if one tier is compromised','Operational Excellence — using infrastructure as code and automation to make infrastructure changes repeatable and auditable','Cost Optimization — consolidating resources into fewer components to reduce the per-unit cost of running the workload'],correct:1,explanation:'Defense in depth applies multiple layers of security controls. Network segmentation (separate VPC subnets per tier, security groups restricting inter-tier traffic, NACLs) limits lateral movement if one tier is compromised — a core security architecture principle in the AWS Well-Architected Security pillar.'},
{id:'ccp204',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company uses on-premises Microsoft Active Directory for authentication. They are deploying an internal web application on AWS and want employees to log in with their existing AD credentials without any re-enrollment. Which approach achieves this with the LEAST operational overhead?',options:['Recreate all AD users as IAM users manually — doubles identity management overhead and requires ongoing synchronization','Deploy Active Directory on EC2 and manually sync user accounts from on-premises — complex to maintain and prone to drift','Use AWS Directory Service AD Connector to proxy authentication requests to on-premises AD without syncing credentials','Create a new Amazon Cognito user pool and import users via CSV — requires re-enrollment and breaks existing AD password policies'],correct:2,explanation:'AD Connector is a proxy that redirects authentication requests to your existing on-premises Active Directory without caching or syncing credentials in AWS. There is no replication to manage and no user re-enrollment — existing AD accounts work immediately for AWS service authentication.'},
{id:'ccp205',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company\'s AWS bill shows $8,000/month in data transfer OUT costs. Their application in us-east-1 serves users primarily in Europe and Asia-Pacific. What architectural change would MOST reduce these costs?',options:['Compress responses with gzip at the application layer — reduces payload size but does not lower data transfer out pricing','Enable S3 Transfer Acceleration — speeds up data uploads to S3 using edge locations; does not reduce outbound egress costs','Deploy CloudFront with edge locations in Europe and Asia-Pacific — serves users from nearby edges, reducing origin egress and per-GB cost','Move the entire application to eu-west-1 — reduces latency for European users but still incurs high egress costs to Asia-Pacific'],correct:2,explanation:'CloudFront\'s per-GB pricing for data delivered to end users is lower than direct EC2/S3 data transfer out rates. More importantly, cache hits serve from the edge with no origin transfer at all. Serving European and APAC users from regional edges rather than us-east-1 reduces both latency and egress costs significantly.'},
{id:'ccp206',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'An auditor requests evidence that no changes have been made to an S3 bucket\'s objects since they were stored — the data must be provably immutable. Which S3 feature provides this guarantee?',options:['S3 Versioning alone — preserves previous object versions but the root user can still delete or overwrite them','S3 Object Lock in Compliance mode with a retention period — prevents any modification or deletion by anyone, including the root user','S3 Default Encryption — encrypts objects at rest but does not prevent authorized users from overwriting or deleting objects','S3 Replication — copies objects to another bucket or region; does not prevent modification of the original objects'],correct:1,explanation:'S3 Object Lock in Compliance mode prevents objects from being deleted or overwritten for the duration of the retention period by anyone, including the root user. This provides WORM (Write Once Read Many) protection suitable for regulatory and audit requirements. Governance mode can be bypassed by users with special permissions; Compliance mode cannot.'},
{id:'ccp207',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company runs a microservices application. Service A calls Service B synchronously, and when Service B is slow, Service A times out and fails too, cascading across the system. Which architectural pattern and AWS service combination addresses this?',options:['Add more EC2 instances to Service B — increases throughput capacity but does not eliminate the synchronous timeout chain','Use Amazon SQS to decouple Service A from Service B asynchronously — Service A enqueues and returns; Service B processes at its pace','Enable Multi-AZ on Service B\'s database — improves database availability but does not address the synchronous coupling between services','Add CloudWatch alarms for Service B latency — provides visibility into the problem but does not resolve the cascading failure pattern'],correct:1,explanation:'Replacing the synchronous call with an SQS queue decouples the services. Service A enqueues messages and returns immediately; Service B processes at its own pace. Load spikes queue rather than cascade. This eliminates the timeout chain and is a core pattern for resilient microservice communication.'},
{id:'ccp208',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company wants to measure and minimize the environmental impact of their AWS workloads. Which Well-Architected pillar provides guidance on this, and which of the following is a recommended practice?',options:['Cost Optimization — recommends purchasing Reserved Instances and right-sizing workloads to reduce AWS spending','Sustainability — recommends using Graviton processors and serverless services to reduce energy consumption per workload','Reliability — recommends deploying across multiple regions to spread load and reduce the environmental impact per region','Performance Efficiency — recommends using larger instances to complete jobs faster and thereby reduce total runtime energy use'],correct:1,explanation:'The Sustainability pillar (added in 2021) focuses on reducing the environmental impact of cloud workloads. Key practices: use AWS Graviton (better performance-per-watt), serverless and managed services (no idle capacity), right-size instances, and use S3 Intelligent-Tiering to avoid storing rarely accessed data on energy-intensive storage.'},
{id:'ccp209',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company needs to run quarterly penetration tests against their own AWS infrastructure. What must they do before beginning?',options:['No action needed — penetration testing is unrestricted on all your own AWS resources by default','Submit a formal AWS penetration testing request form and wait for explicit approval before testing any service','Review AWS\'s Penetration Testing policy — most services are permitted without approval; DoS simulation and DNS zone walking remain prohibited','Purchase AWS Shield Advanced — Shield Advanced includes a DDoS Response Team but does not grant penetration testing permissions'],correct:2,explanation:'AWS\'s current penetration testing policy permits customers to test their own resources for most services (EC2, RDS, CloudFront, API Gateway, Lambda, Lightsail, Elastic Beanstalk) without pre-approval. However, prohibited activities include DDoS simulation against AWS infrastructure, DNS zone walking, and port/protocol flooding. Always review the current AWS Customer Support Policy for Penetration Testing before starting.'},
{id:'ccp210',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company ingests clickstream data from 50,000 concurrent users in real time. They need to aggregate this data every 5 minutes and store results in a data warehouse for business intelligence queries. Which pipeline is MOST appropriate?',options:['Users → SQS → Lambda → RDS — SQS can buffer but Lambda writing to RDS cannot handle 50,000 concurrent users cost-effectively','Users → Kinesis Data Streams → Kinesis Data Firehose → Redshift — purpose-built real-time ingestion pipeline for streaming-to-data-warehouse','Users → S3 → Athena → QuickSight — works for batch analytics on existing S3 data; not suitable for 5-minute real-time aggregation','Users → DynamoDB Streams → Lambda → S3 — event-driven but requires complex Lambda logic and lacks native Redshift delivery'],correct:1,explanation:'Kinesis Data Streams ingests high-volume real-time streaming data. Kinesis Data Firehose buffers and delivers it to Redshift in micro-batches (configurable interval, e.g., every 5 minutes) without custom code. Redshift serves BI queries. This is the purpose-built AWS pattern for streaming-to-data-warehouse pipelines.'},
{id:'ccp211',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company has been running on AWS for 2 years. They have consistent EC2 usage but have never purchased Reserved Instances. AWS Cost Explorer\'s RI recommendations show potential savings of $4,200/month with a 12-month Standard RI commitment. The break-even is 7 months. What should the company consider before purchasing?',options:['Reserved Instances cannot be resold so a long commitment is always too risky regardless of workload stability','Evaluate workload consistency — with 2 years of stable usage and 7-month break-even, a 12-month RI is sound; unused RIs can be sold on the RI Marketplace','Reserved Instances always require full upfront payment with no monthly or partial payment options available','Purchase 3-year RIs immediately for maximum savings regardless of workload stability or future business direction'],correct:1,explanation:'The key consideration for Reserved Instances is workload stability over the commitment period. With break-even at 7 months and consistent 2-year history, a 12-month RI is financially sound. If needs change, Standard RIs can be sold on the RI Marketplace. 3-year commitments maximize savings but reduce flexibility — appropriate only for very stable, long-running workloads.'},
{id:'ccp212',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company wants to allow their mobile app users to upload photos directly to S3 without routing the upload through their application servers (to reduce server load and cost). How can they accomplish this securely?',options:['Make the S3 bucket public with an object prefix — exposes all objects in the bucket to anyone on the internet','Generate a pre-signed S3 URL server-side with a short TTL — grants temporary PUT permission to a specific object without exposing the bucket','Issue all users permanent IAM access keys with S3 write permissions — long-lived credentials are difficult to manage and rotate','Use AWS Transfer Family SFTP endpoint — designed for managed file transfers via SFTP, not client-side browser uploads'],correct:1,explanation:'A pre-signed URL is generated by the server using AWS credentials, granting the bearer temporary permission to perform a specific S3 operation (PUT) on a specific object for a limited time. The client uploads directly to S3 without the server handling the payload. The bucket remains private and the URL expires, preventing abuse.'},
{id:'ccp213',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company is evaluating two DR strategies. Strategy A (Pilot Light) keeps a minimal version of the environment running in AWS. Strategy B (Warm Standby) keeps a scaled-down but fully functional copy running. How do these compare in terms of RTO and cost?',options:['Pilot Light and Warm Standby have identical RTO and monthly operating cost since both run partial environments','Pilot Light has lower running cost but higher RTO (must provision resources); Warm Standby costs more but achieves lower RTO','Warm Standby is cheaper because its scaled-down environment consumes fewer resources than a Pilot Light configuration','Pilot Light achieves a lower RTO because fewer running components means the recovery process is simpler and faster'],correct:1,explanation:'Pilot Light: only critical core components run (e.g., DB replication), other components must be provisioned/scaled during recovery → lower cost, higher RTO. Warm Standby: a fully functional but scaled-down version runs continuously → faster RTO (just scale up), but higher ongoing cost. The four DR strategies in order of cost/RTO: Backup & Restore → Pilot Light → Warm Standby → Multi-Site Active/Active.'},
{id:'ccp214',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company runs a multi-account AWS environment. A developer in Account A needs to access an S3 bucket in Account B. They should not need permanent IAM credentials. What is the RECOMMENDED approach?',options:['Create an IAM user in Account B and share the access keys — shares long-lived static credentials, a security anti-pattern','Make the S3 bucket in Account B publicly accessible — exposes data to the entire internet, not just the authorized developer','Create a cross-account IAM Role in Account B with a trust policy, and have the developer assume it via STS for temporary credentials','Copy all data from Account B\'s S3 bucket to Account A weekly — causes data drift and wastes storage costs on duplicated data'],correct:2,explanation:'Cross-account IAM roles are the AWS-recommended pattern for cross-account access. The role in Account B trusts Account A\'s principal; the developer assumes the role via STS:AssumeRole, receiving temporary credentials scoped to the role\'s permissions. No permanent credentials are shared, and access can be revoked by modifying the role.'},
{id:'ccp215',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company runs thousands of IoT sensors that send temperature readings every second. They need to detect when any sensor exceeds 80°C within 10 seconds of the reading and trigger an alert. Which architecture achieves this with the LOWEST latency?',options:['Sensors → S3 → Athena query every minute — introduces up to 60 seconds of latency; S3 batch processing is not real-time','Sensors → AWS IoT Core → IoT Rules Engine → SNS alert — the Rules Engine evaluates each message in real time, triggering SNS within seconds','Sensors → SQS → Lambda → DynamoDB → CloudWatch alarm — introduces queue polling delays and a batch alarm evaluation cycle','Sensors → Kinesis → Redshift → QuickSight dashboard — streams data to a data warehouse for BI; not designed for real-time alerting'],correct:1,explanation:'AWS IoT Core ingests device data and the IoT Rules Engine evaluates SQL-like rules in real time against incoming messages. A rule like "SELECT * FROM sensors WHERE temperature > 80" triggers immediately on each message meeting the condition, invoking SNS for instant alerting — sub-second end-to-end, no batch processing.'},
{id:'ccp216',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company is building a new application and cannot yet predict traffic patterns. They want to avoid over-provisioning but also avoid performance issues. Which combination of services and pricing models best handles this uncertainty at launch?',options:['Commit to Reserved Instances for all components upfront — locks in cost without data to justify what to reserve','Over-provision at 10x expected peak with On-Demand — avoids shortfalls but wastes significant budget on idle capacity','Use On-Demand with Auto Scaling at launch — pay only for actual usage and gather real traffic data before any RI commitment','Use Spot Instances for all components — maximum savings but interruptions could affect a new, customer-facing workload'],correct:2,explanation:'For unpredictable new workloads, On-Demand + Auto Scaling is the right starting point: you pay only for what you use and auto-scale to match demand. After gathering 1-2 months of CloudWatch metrics, Cost Explorer\'s RI recommendations will be based on actual usage patterns, making any Reserved Instance commitment well-informed.'},
{id:'ccp217',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company needs to run a legacy Windows application that requires a specific version of Windows Server and has a license tied to the physical host (BYOL). They want to move this to AWS with the minimum licensing change. Which EC2 option is required?',options:['Spot Instance with a Windows AMI — can be interrupted by AWS at any time; does not support host-level BYOL licensing','On-Demand Instance with Multi-AZ deployment — runs on shared AWS host hardware; host identity changes on stop/start','Dedicated Host — a physical server fully dedicated to your use, required for per-socket or per-core BYOL Windows Server licenses','Reserved Instance with default tenancy — still runs on shared AWS hardware; does not satisfy host-bound licensing requirements'],correct:2,explanation:'Dedicated Hosts provide a physical EC2 server fully dedicated to your use, allowing you to use your existing per-socket or per-core server-bound Windows Server licenses (BYOL). Standard EC2 instances run on shared hardware with shared host identity, which doesn\'t satisfy host-based licensing requirements.'},
{id:'ccp218',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company\'s application must comply with a regulation requiring all customer data to remain within the European Union. Architects need to ensure no data replication outside EU regions occurs. Which AWS mechanisms enforce this?',options:['S3 Block Public Access prevents objects from being made public within a region but does not restrict cross-region replication','AWS automatically keeps data in the region where it\'s stored — cross-region features must be explicitly configured by customers','Service Control Policies restricting resource creation to EU regions, combined with explicit opt-in for any cross-region replication features','AWS CloudTrail data residency mode — CloudTrail does not have a residency mode; it records API calls for audit purposes'],correct:2,explanation:'AWS does not move data between regions without explicit customer action, but cross-region features (S3 CRR, RDS cross-region replicas, CloudFront) can be configured accidentally. SCPs denying resource creation outside approved EU regions (eu-west-1, eu-central-1, etc.) prevent developers from accidentally enabling cross-region replication to non-EU destinations.'},
{id:'ccp219',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company enables AWS Config and discovers that 15 EC2 security groups allow unrestricted SSH access (0.0.0.0/0 on port 22). They want this automatically fixed whenever it\'s detected. Which Config feature enables automatic remediation?',options:['Configure AWS Config snapshot delivery to S3 — archives configuration history but does not evaluate or remediate violations','Enable Config Conformance Packs with manual review — packages multiple rules together but relies on human action to remediate','Configure an AWS Config rule with an automatic remediation action linked to an SSM Automation runbook to fix violations','Set up AWS Trusted Advisor with email notifications — surfaces best-practice issues weekly but cannot auto-remediate them'],correct:2,explanation:'AWS Config rules evaluate resource configurations continuously. When a rule (like restricted-ssh) marks a resource as NON_COMPLIANT, a remediation action linked to an SSM Automation runbook can automatically fix it — in this case, removing the 0.0.0.0/0 port 22 ingress rule. This closes the loop from detect to remediate without human intervention.'},
{id:'ccp220',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company\'s application stores user-uploaded videos in S3. After upload, videos must be transcoded to multiple resolutions. Transcoding takes 5-30 minutes per video. On busy days, hundreds of videos are uploaded simultaneously. Which architecture handles this elastically without managing servers?',options:['EC2 instance polling S3 every minute — introduces up to 60 seconds of delay per upload and wastes compute during idle periods','S3 Event Notification → SQS queue → Auto Scaling EC2 worker fleet polling the queue and scaling with depth → output to S3','RDS trigger invoking an EC2 transcoding cluster — RDS does not trigger on S3 events; transcoding logic must live at the application layer','CloudFront → Lambda → ffmpeg — Lambda has a 15-minute timeout; 30-minute transcoding jobs cannot complete within Lambda\'s limit'],correct:1,explanation:'S3 events notify SQS immediately on upload. An Auto Scaling group of EC2 workers (or ECS tasks) polls the SQS queue — scaling out as the queue depth grows, scaling in when it drains. This handles burst without managing a fixed server pool and uses SQS as a durable buffer so no uploads are lost during scale-out.'},
{id:'ccp221',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'A company receives an unexpectedly high AWS bill. Cost Explorer shows a spike in data transfer costs from an EC2 instance in us-east-1. Upon investigation, the instance is sending large amounts of data to an external IP not belonging to the company. Which service would have alerted them to this anomaly EARLIEST?',options:['AWS Budgets cost alert — triggers only after the billing period accumulates spend; does not detect behavioral anomalies in real time','Amazon GuardDuty — analyzes VPC Flow Logs and DNS logs in real time using ML to detect data exfiltration patterns immediately','AWS Cost Anomaly Detection — identifies unusual spending patterns as costs accumulate; detects the financial impact, not the behavior','AWS Trusted Advisor — provides weekly cost optimization recommendations; not designed for real-time threat or anomaly detection'],correct:1,explanation:'GuardDuty analyzes VPC Flow Logs and DNS logs in real time, with ML models specifically designed to detect data exfiltration patterns (unusual outbound traffic volume or destination). It would alert during the incident. Cost Anomaly Detection catches the financial impact after some spend accumulates. Budgets only alert on total cost thresholds, not behavior patterns.'},
{id:'ccp222',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company wants to migrate their on-premises MySQL database to AWS with minimal downtime — the database must remain online and accepting writes throughout the migration. Which service supports continuous replication from on-premises to RDS with near-zero downtime cutover?',options:['AWS Snowball Edge — ships data physically; takes days to arrive and cannot be used for live database migration with writes','AWS DataSync — transfers files between on-premises storage and AWS; not designed for live database migration with CDC','AWS Database Migration Service (DMS) with CDC — performs an initial load then continuously replicates writes until cutover','AWS Backup — creates point-in-time snapshots for restore; the source database must be offline during restoration'],correct:2,explanation:'AWS DMS performs an initial full load of existing data, then uses Change Data Capture (CDC) to continuously replicate ongoing writes from the source to the target. The source database stays live. When replication lag reaches near-zero, you cutover with minimal downtime — often under a minute for the final DNS/connection switch.'},
{id:'ccp223',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company\'s architecture review identifies that all application data is stored in a single us-east-1 Availability Zone. The team argues that because they use RDS Multi-AZ, they are fully protected. What is the flaw in this reasoning?',options:['There is no flaw — RDS Multi-AZ provides automatic failover protecting all application tiers from Availability Zone failures','RDS Multi-AZ protects the database tier only; EC2 web servers, load balancers, and other single-AZ components remain as SPOFs','Multi-AZ deployment doubles the database cost, which is a financial risk that should be weighed against the availability benefit','RDS Multi-AZ replicates synchronously to a standby; the team may have confused this with asynchronous read replica replication'],correct:1,explanation:'RDS Multi-AZ provides automatic failover for the database tier only. If the EC2 instances, load balancer, or other application components are in a single AZ, those remain SPOFs. True AZ-level fault tolerance requires ALL tiers to be distributed across multiple AZs — EC2 Auto Scaling across AZs, ALB spanning multiple AZs, and RDS Multi-AZ together.'},
{id:'ccp224',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company wants to enforce that all IAM users in their account must have MFA enabled before they can perform any actions beyond viewing their own MFA settings. How is this typically implemented?',options:['AWS automatically enforces MFA for all IAM users in the account once MFA is configured at the account level','Attach an IAM Deny policy to all users or a group — denies all actions when aws:MultiFactorAuthPresent is false, except MFA self-enrollment','Manually enable MFA for each user in the AWS Console — effective but does not prevent users from acting before MFA is enabled','Purchase AWS Shield Advanced — provides DDoS protection; has no capability for IAM MFA enforcement or policy management'],correct:1,explanation:'The standard pattern is an IAM policy with a condition: "Effect": "Deny" on all actions except iam:CreateVirtualMFADevice and iam:EnableMFADevice when the condition "Bool": {"aws:MultiFactorAuthPresent": "false"}. Attaching this to an "all users" group creates a self-service MFA enforcement gate without admin intervention per user.'},
{id:'ccp225',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A startup builds a REST API on API Gateway + Lambda. During load testing, they observe cold start latency of 800ms for the first request after a period of inactivity, impacting user experience. Which Lambda feature directly addresses this?',options:['Increase Lambda memory to the maximum (10 GB) — increases compute speed but does not eliminate cold start initialization time','Enable Lambda Provisioned Concurrency — pre-initializes execution environments so they respond immediately with no cold start delay','Shorten the Lambda timeout value — reduces the maximum allowed runtime but does not eliminate cold start latency on first invocation','Switch to Lambda@Edge — runs Lambda at CloudFront edge locations; still subject to cold starts and limited to 30 seconds maximum'],correct:1,explanation:'Lambda Provisioned Concurrency pre-initializes a specified number of execution environments so they are ready to respond instantly with no cold start delay. It eliminates the initialization time for those reserved instances. This has a cost (you pay for provisioned concurrency even when idle), so it\'s used for latency-sensitive endpoints.'},
{id:'ccp226',exams:['ccp'],domain:'Billing & Pricing',difficulty:'hard',text:'An organization uses AWS Organizations with 20 member accounts. They apply the following policy hierarchy: Root SCP allows all actions; OU-level SCP denies EC2 in ap-southeast-1; Account-level SCP denies S3 DeleteObject. An IAM admin in a member account tries to launch EC2 in ap-southeast-1. What happens?',options:['The launch succeeds — the root SCP allows all actions and always takes precedence over lower-level SCP restrictions','The launch fails — the OU-level SCP denial overrides all allows; explicit deny anywhere in the SCP chain blocks the action','The outcome depends on whether the IAM admin user has explicit EC2:RunInstances permission in their IAM policy','The launch succeeds if and only if the admin user has AdministratorAccess attached to their IAM principal'],correct:1,explanation:'SCP evaluation uses intersection logic: a principal must be allowed at EVERY level (Root → OU → Account) and by their IAM policy. An explicit Deny anywhere in the SCP hierarchy overrides all Allows regardless of the principal\'s IAM permissions. The OU-level denial of EC2 in ap-southeast-1 blocks the action even for account administrators.'},
{id:'ccp227',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A company needs to run a containerized application that scales from zero to thousands of concurrent tasks during business hours and back to zero overnight. Minimizing cost during off-hours is critical. Which compute option is BEST?',options:['EC2 Reserved Instances running 24/7 — pay for all instances continuously even when zero tasks run overnight','Amazon ECS with AWS Fargate — serverless containers that scale to zero overnight with no compute charges during idle periods','Amazon EKS with self-managed EC2 node groups — EC2 nodes incur charges whether or not any container tasks are running','EC2 Auto Scaling with a minimum of 10 instances — still pays for 10 instances overnight even when no workload is present'],correct:1,explanation:'Fargate is serverless for containers — you pay only for vCPU and memory consumed while tasks are running. When scaled to zero (no running tasks), there is no charge. This is the optimal model for bursty, variable-duration workloads with long idle periods. EC2-based options always incur cost for the underlying instances even when idle.'},
{id:'ccp228',exams:['ccp'],domain:'Cloud Concepts',difficulty:'hard',text:'A company is planning a migration and categorizes each application into one of the 6 Rs. Their custom-built CRM is costly to maintain, and a SaaS alternative exists. Which migration strategy applies?',options:['Rehost — move the CRM to EC2 with no changes, maintaining the same architecture and operational complexity','Replatform — migrate the CRM to a managed service like RDS, making targeted improvements without rebuilding it','Repurchase — replace the custom CRM with a SaaS alternative like Salesforce, eliminating ongoing maintenance entirely','Re-architect — rewrite the CRM as cloud-native microservices on AWS, the highest effort but most cloud-optimized outcome'],correct:2,explanation:'Repurchase (also called "drop and shop") means replacing an existing application with a commercial off-the-shelf or SaaS product. Moving from a custom CRM to Salesforce is the canonical example. It eliminates maintenance burden immediately at the cost of migration effort and potential feature differences.'},
{id:'ccp229',exams:['ccp'],domain:'Security & Compliance',difficulty:'hard',text:'A company hosts a public API on API Gateway. They begin receiving requests that appear to be from automated bots scraping their data at 10,000 requests per second from a small set of IP addresses. Which TWO controls should they implement immediately? (Select the best combined answer.)',options:['Enable CloudTrail logging and review logs manually — useful for forensics after the fact but does not stop active bot traffic','Attach a WAF Web ACL to API Gateway with an IP-based rate limit rule and an IP set rule blocking the known offending IPs','Increase API Gateway throttling limits to handle the extra load — allows the scraping to continue and increases origin server cost','Enable AWS Shield Standard — protects against DDoS volumetric attacks at the network layer; does not block application-layer bots'],correct:1,explanation:'AWS WAF on API Gateway provides: (1) IP set rules to block known malicious IPs immediately; (2) rate-based rules to automatically block any IP exceeding a request threshold (e.g., 1,000/5 min). These take effect in minutes. Shield Standard protects against DDoS volumetric attacks but is not designed for application-layer bot scraping patterns.'},
{id:'ccp230',exams:['ccp'],domain:'Technology',difficulty:'hard',text:'A financial services company needs to maintain a complete, tamper-proof audit log of every transaction processed by their application. The log must be cryptographically verifiable — it must be provable that no record was altered or deleted after the fact. Which AWS service is PURPOSE-BUILT for this requirement?',options:['Amazon CloudWatch Logs with S3 export — durable log storage but CloudWatch does not cryptographically chain log entries','Amazon S3 with versioning enabled — preserves object history but S3 does not provide cryptographic proof of record integrity','Amazon QLDB (Quantum Ledger Database) — purpose-built immutable ledger with SHA-256 cryptographic chaining of every transaction','AWS CloudTrail with log file validation — validates that CloudTrail log files were not tampered with; does not cover application transaction logs'],correct:2,explanation:'Amazon QLDB is a fully managed ledger database with a built-in immutable journal. Every change is cryptographically chained (SHA-256 hash of each block includes the hash of the previous block), so any alteration to historical records is mathematically detectable. It\'s purpose-built for financial transactions, supply chain, and any application requiring a verifiable audit trail.'},
];
